"""
Parameterized generator for GH463_napari_8772.

Source PR:    https://github.com/napari/napari/pull/8772
Source Issue: https://github.com/napari/napari/issues/8771

Seed varies: renames 'across' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH463_napari_8772'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH463_napari_8772'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('across', 'across' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH463_napari_8772',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'napari/napari',
                "pr_number": 8772,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/napari/napari/pull/8772",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'src/napari/_qt/_tests/test_qt_viewer.py': 'from __future__ import annotations\n\nimport gc\nimport os\nimport typing\nfrom itertools import product, takewhile\nfrom math import isclose\nfrom unittest import mock\n\nimport numpy as np\nimport numpy.testing as npt\nimport pytest\nfrom imageio import imread\nfrom pytestqt.qtbot import QtBot\nfrom qtpy.QtWidgets import QApplication, QMessageBox\nfrom scipy import ndimage as ndi\nfrom vispy.app import MouseEvent\n\nfrom napari._qt.qt_viewer import QtViewer\nfrom napari._tests.utils import (\n    add_layer_by_type,\n    check_viewer_functioning,\n    layer_test_data,\n    skip_local_popups,\n    skip_on_win_ci,\n)\nfrom napari._vispy._tests.utils import vispy_image_scene_size\nfrom napari.components.viewer_model import ViewerModel\nfrom napari.layers import Labels, Layer, Points\nfrom napari.settings import get_settings\nfrom napari.utils.colormaps import DirectLabelColormap, label_colormap\nfrom napari.utils.interactions import mouse_press_callbacks\n\nif typing.TYPE_CHECKING:\n    from pathlib import Path\n\n    from numpy.typing import ArrayLike\n    from pytestqt.qtbot import QtBot\n\nBUILTINS_DISP = \'napari\'\nBUILTINS_NAME = \'builtins\'\nNUMPY_INTEGER_TYPES = [\n    np.int8,\n    np.int16,\n    np.int32,\n    np.int64,\n    np.uint8,\n    np.uint16,\n    np.uint32,\n    np.uint64,\n]\n\n\n@pytest.fixture\ndef qt_viewer(\n    qtbot: QtBot, qt_viewer_: QtViewer, request: pytest.FixtureRequest\n) -> QtViewer:\n    if \'show_qt_viewer\' in request.keywords:\n        qt_viewer_.show()\n        qt_viewer_.resize(460, 460)\n        QApplication.processEvents()\n        qtbot.wait_exposed(qt_viewer_)\n    return qt_viewer_\n\n\n@pytest.mark.parametrize((\'layer_class\', \'data\', \'ndim\'), layer_test_data)\ndef test_add_layer(\n    qt_viewer: QtViewer,\n    viewer_model: ViewerModel,\n    layer_class: type[Layer],\n    data: ArrayLike,\n    ndim: int,\n) -> None:\n    viewer_model.dims.ndisplay = max(min(3, ndim), 2)\n\n    add_layer_by_type(viewer_model, layer_class, data)\n    check_viewer_functioning(viewer_model, qt_viewer, data, ndim)\n\n\ndef test_new_labels(qt_viewer: QtViewer, viewer_model: ViewerModel) -> None:\n    """Test adding new labels layer to empty viewer."""\n    viewer_model._new_labels()\n    assert np.max(viewer_model.layers[0].data) == 0\n    assert len(viewer_model.layers) == 1\n    assert qt_viewer.layers.model().rowCount() == len(viewer_model.layers)\n\n    assert viewer_model.dims.ndim == 2\n    assert qt_viewer.dims.nsliders == viewer_model.dims.ndim\n    npt.assert_array_equal(qt_viewer.dims._displayed_sliders, False)\n\n\ndef test_new_labels_to_image(\n    qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    """Test adding new labels layer to viewer with image."""\n    data = np.random.default_rng(0).random((10, 15))\n    viewer_model.add_image(data)\n    viewer_model._new_labels()\n    assert np.max(viewer_model.layers[1].data) == 0\n    assert len(viewer_model.layers) == 2\n    assert qt_viewer.layers.model().rowCount() == len(viewer_model.layers)\n\n    assert viewer_model.dims.ndim == 2\n    assert qt_viewer.dims.nsliders == viewer_model.dims.ndim\n    npt.assert_array_equal(qt_viewer.dims._displayed_sliders, False)\n\n\ndef test_new_points(qt_viewer: QtViewer, viewer_model: ViewerModel) -> None:\n    """Test adding a new points layer to empty viewer."""\n    viewer_model.add_points()\n    assert len(viewer_model.layers[0].data) == 0\n    assert len(viewer_model.layers) == 1\n    assert qt_viewer.layers.model().rowCount() == len(viewer_model.layers)\n\n    assert viewer_model.dims.ndim == 2\n    assert qt_viewer.dims.nsliders == viewer_model.dims.ndim\n    npt.assert_array_equal(qt_viewer.dims._displayed_sliders, False)\n\n\ndef test_new_points_to_image(\n    qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    """Test adding new points layer to viewer with image."""\n    data = np.random.default_rng(0).random((10, 15))\n    viewer_model.add_image(data)\n    viewer_model.add_points()\n    assert len(viewer_model.layers[1].data) == 0\n    assert len(viewer_model.layers) == 2\n    assert qt_viewer.layers.model().rowCount() == len(viewer_model.layers)\n\n    assert viewer_model.dims.ndim == 2\n    assert qt_viewer.dims.nsliders == viewer_model.dims.ndim\n    npt.assert_array_equal(qt_viewer.dims._displayed_sliders, False)\n\n\ndef test_new_shapes_empty_viewer(\n    qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    """Test adding new shapes layer to empty viewer."""\n    viewer_model.add_shapes()\n    assert len(viewer_model.layers[0].data) == 0\n    assert len(viewer_model.layers) == 1\n    assert qt_viewer.layers.model().rowCount() == len(viewer_model.layers)\n\n    assert viewer_model.dims.ndim == 2\n    assert qt_viewer.dims.nsliders == viewer_model.dims.ndim\n    npt.assert_array_equal(qt_viewer.dims._displayed_sliders, False)\n\n\ndef test_new_shapes_to_image(\n    qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    """Test adding new shapes layer to viewer with image."""\n    data = np.random.default_rng(0).random((10, 15))\n    viewer_model.add_image(data)\n    viewer_model.add_shapes()\n    assert len(viewer_model.layers[1].data) == 0\n    assert len(viewer_model.layers) == 2\n    assert qt_viewer.layers.model().rowCount() == len(viewer_model.layers)\n\n    assert viewer_model.dims.ndim == 2\n    assert qt_viewer.dims.nsliders == viewer_model.dims.ndim\n    npt.assert_array_equal(qt_viewer.dims._displayed_sliders, False)\n\n\ndef test_z_order_adding_removing_images(\n    viewer_model: ViewerModel, qt_viewer: QtViewer\n) -> None:\n    """Test z order is correct after adding/ removing images."""\n    data = np.ones((10, 10))\n\n    vis = qt_viewer.canvas.layer_to_visual\n    viewer_model.add_image(data, colormap=\'red\', name=\'red\')\n    viewer_model.add_image(data, colormap=\'green\', name=\'green\')\n    viewer_model.add_image(data, colormap=\'blue\', name=\'blue\')\n    order = [vis[x].order for x in viewer_model.layers]\n    np.testing.assert_almost_equal(\n        order, list(range(len(viewer_model.layers)))\n    )\n\n    # Remove and re-add image\n    viewer_model.layers.remove(\'red\')\n    order = [vis[x].order for x in viewer_model.layers]\n    np.testing.assert_almost_equal(\n        order, list(range(len(viewer_model.layers)))\n    )\n    viewer_model.add_image(data, colormap=\'red\', name=\'red\')\n    order = [vis[x].order for x in viewer_model.layers]\n    np.testing.assert_almost_equal(\n        order, list(range(len(viewer_model.layers)))\n    )\n\n    # Remove two other images\n    viewer_model.layers.remove(\'green\')\n    viewer_model.layers.remove(\'blue\')\n    order = [vis[x].order for x in viewer_model.layers]\n    np.testing.assert_almost_equal(\n        order, list(range(len(viewer_model.layers)))\n    )\n\n    # Add two other layers back\n    viewer_model.add_image(data, colormap=\'green\', name=\'green\')\n    viewer_model.add_image(data, colormap=\'blue\', name=\'blue\')\n    order = [vis[x].order for x in viewer_model.layers]\n    np.testing.assert_almost_equal(\n        order, list(range(len(viewer_model.layers)))\n    )\n\n\n@pytest.mark.show_qt_viewer\ndef test_export_figure(\n    qt_viewer: QtViewer,\n    viewer_model: ViewerModel,\n    tmp_path: Path,\n    qtbot: QtBot,\n) -> None:\n    # Add image\n    data = np.ones((250, 250))\n    layer = viewer_model.add_image(data)\n\n    camera_center = viewer_model.camera.center\n    camera_zoom = viewer_model.camera.zoom\n    img = qt_viewer.export_figure(flash=False, path=str(tmp_path / \'img.png\'))\n\n    assert viewer_model.camera.center == camera_center\n    assert isclose(viewer_model.camera.zoom, camera_zoom)\n    np.testing.assert_allclose(img.shape, (250, 250, 4), atol=1)\n\n    assert (img.reshape(-1, 4) == [255, 255, 255, 255]).all(axis=1).all()\n\n    assert (tmp_path / \'img.png\').exists()\n\n    layer.scale = [0.12, 0.24]\n    img = qt_viewer.export_figure(flash=False)\n    # allclose accounts for rounding errors when computing size in hidpi aka\n    # retina displays\n    np.testing.assert_allclose(img.shape, (250, 500, 4), atol=1)\n\n    layer.scale = [0.12, 0.12]\n    img = qt_viewer.export_figure(flash=False)\n    np.testing.assert_allclose(img.shape, (250, 250, 4), atol=1)\n\n\n@pytest.mark.show_qt_viewer\ndef test_export_figure_3d(\n    qt_viewer: QtViewer,\n    viewer_model: ViewerModel,\n    tmp_path: Path,\n    qtbot: QtBot,\n) -> None:\n    rng = np.random.default_rng(0)\n    # Add image, keep values low to contrast with white background\n    viewer_model.dims.ndisplay = 3\n    viewer_model.theme = \'light\'\n\n    data = rng.integers(50, 100, size=(10, 250, 250), dtype=np.uint8)\n    layer = viewer_model.add_image(data)\n\n    # check the non-rotated data (angles = 0,0,90) are exported without any\n    # visible background, since the margins should be 0\n    img = qt_viewer.export_figure(flash=False)\n    np.testing.assert_allclose(img.shape, (250, 250, 4), atol=1)\n\n    # check that changing the scale still gives the pixel size\n    layer.scale = [1, 0.12, 0.24]\n    img = qt_viewer.export_figure(flash=False)\n    np.testing.assert_allclose(img.shape, (250, 500, 4), atol=1)\n    layer.scale = [1, 1, 1]\n\n    # rotate the data, export the figure, and check that the rotated figure\n    # shape is greater than the original data shape\n    viewer_model.camera.angles = (45, 45, 45)\n    img = qt_viewer.export_figure(flash=False)\n    np.testing.assert_allclose(img.shape, (255, 258, 4), atol=1)\n\n    # FIXME: Changes introduced in #7870 slightly changed the timing and result in a blank canvas.\n    # Probably related to #8033. Because canvass size is still correct, we know it would look alright\n    # The theme is dark, so the canvas will be white. Test that the image\n    # has a white background, roughly more background than the data itself.\n    # assert (img[img > 250].shape[0] / img[img <= 200].shape[0]) > 0.5\n\n\n@pytest.mark.show_qt_viewer\ndef test_export_rois(\n    qt_viewer: QtViewer,\n    viewer_model: ViewerModel,\n    tmp_path: Path,\n    qtbot: QtBot,\n) -> None:\n    # Create an image with a defined shape (100x100) and a square in the middle\n\n    img = np.zeros((100, 100), dtype=np.uint8)\n    img[25:75, 25:75] = 255\n\n    # Add viewer\n    viewer_model.add_image(img, colormap=\'gray\')\n\n    # Create a couple of clearly defined rectangular polygons for validation\n    roi_shapes_data = [\n        np.array([[0, 0], [20, 0], [20, 20], [0, 20]]) - (0.5, 0.5),\n        np.array([[15, 15], [35, 15], [35, 35], [15, 35]]) - (0.5, 0.5),\n        np.array([[65, 65], [85, 65], [85, 85], [65, 85]]) - (0.5, 0.5),\n        np.array([[15, 65], [35, 65], [35, 85], [15, 85]]) - (0.5, 0.5),\n        np.array([[65, 15], [85, 15], [85, 35], [65, 35]]) - (0.5, 0.5),\n        np.array([[40, 40], [60, 40], [60, 60], [40, 60]]) - (0.5, 0.5),\n    ]\n    paths = [\n        str(tmp_path / f\'roi_{i}.png\') for i in range(len(roi_shapes_data))\n    ]\n\n    # Save original camera state for comparison later\n    camera_center = viewer_model.camera.center\n    camera_zoom = viewer_model.camera.zoom\n\n    with pytest.raises(ValueError, match=\'The number of file\'):\n        qt_viewer.export_rois(roi_shapes_data, paths=paths + [\'fake\'])\n    # Export ROI to image path\n    test_roi = qt_viewer.export_rois(roi_shapes_data, paths=paths)\n    qtbot.wait(10)\n\n    assert all(\n        (tmp_path / f\'roi_{i}.png\').exists()\n        for i in range(len(roi_shapes_data))\n    )\n\n    # This test uses scaling to adjust the expected size of ROI images\n    # and number of white pixels in the ROI screenshots\n    # The assertion may fail if the test is run on screens with fractional scaling.\n    scaling = qt_viewer.screen().devicePixelRatio()\n\n    assert all(\n        roi.shape == (20 * scaling, 20 * scaling, 4) for roi in test_roi\n    )\n    assert viewer_model.camera.center == camera_center\n    assert viewer_model.camera.zoom == camera_zoom\n\n    test_dir = tmp_path / \'test_dir\'\n    refs = []\n    import gc\n\n    try:\n        qtbot.wait(1000)\n        res = qt_viewer.export_rois(roi_shapes_data, paths=test_dir)\n        refs.append(res)\n        gc.collect()\n        QApplication.processEvents()\n        qtbot.wait(1000)\n    finally:\n        res.clear()\n        gc.collect()\n\n    assert all(\n        (test_dir / f\'roi_{i}.png\').exists()\n        for i in range(len(roi_shapes_data))\n    )\n    expected_values = [0, 100, 100, 100, 100, 400]\n    for index, roi_img in enumerate(test_roi):\n        gray_img = roi_img[..., 0]\n        assert (\n            np.count_nonzero(gray_img) == expected_values[index] * scaling**2\n        ), f\'Wrong number of white pixels in the ROI {index}\'\n\n\n@pytest.mark.show_qt_viewer\ndef test_export_rois_3d_fail(\n    qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    # create 3d ROI for testing\n    roi_3d = [\n        np.array([[0, 0, 0], [0, 20, 0], [0, 20, 20], [0, 0, 20]]),\n        np.array([[0, 15, 15], [0, 35, 15], [0, 35, 35], [0, 15, 35]]),\n    ]\n\n    # Only 2D roi supported at the moment\n    with pytest.raises(ValueError, match=\'ROI found with invalid\'):\n        qt_viewer.export_rois(roi_3d)\n\n    test_data = np.zeros((4, 50, 50))\n    viewer_model.add_image(test_data)\n    viewer_model.dims.ndisplay = 3\n\n    # 3D view should fail\n    roi_data = [\n        np.array([[0, 0], [20, 0], [20, 20], [0, 20]]),\n        np.array([[15, 15], [35, 15], [35, 35], [15, 35]]),\n    ]\n    with pytest.raises(\n        NotImplementedError, match="\'export_rois\' is not implemented"\n    ):\n        qt_viewer.export_rois(roi_data)\n\n\n@pytest.mark.skip(\'new approach\')\n@pytest.mark.show_qt_viewer\ndef test_screenshot_dialog(\n    viewer_model: ViewerModel, qt_viewer: QtViewer, tmp_path: Path\n) -> None:\n    """Test save screenshot functionality."""\n    rng = np.random.default_rng(0)\n    # Add image\n    data = rng.random((10, 15))\n    viewer_model.add_image(data)\n\n    # Add labels\n    data = rng.integers(20, size=(10, 15))\n    viewer_model.add_labels(data)\n\n    # Add points\n    data = 20 * rng.random((10, 2))\n    viewer_model.add_points(data)\n\n    # Add vectors\n    data = 20 * rng.random((10, 2, 2))\n    viewer_model.add_vectors(data)\n\n    # Add shapes\n    data = 20 * rng.random((10, 4, 2))\n    viewer_model.add_shapes(data)\n\n    # Save screenshot\n    input_filepath = os.path.join(tmp_path, \'test-save-screenshot\')\n    mock_return = (input_filepath, \'\')\n    with (\n        mock.patch(\'napari._qt._qt_viewer.QFileDialog\') as mocker,\n        mock.patch(\'napari._qt._qt_viewer.QMessageBox\') as mocker2,\n    ):\n        mocker.getSaveFileName.return_value = mock_return\n        mocker2.warning.return_value = QMessageBox.Yes\n        qt_viewer._screenshot_dialog()\n\n    # Assert behaviour is correct\n    expected_filepath = input_filepath + \'.png\'  # add default file extension\n    assert os.path.exists(expected_filepath)\n    output_data = imread(expected_filepath)\n    expected_data = qt_viewer.screenshot(flash=False)\n    assert np.allclose(output_data, expected_data)\n\n\n@pytest.mark.key_bindings\ndef test_active_keybindings(\n    qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    """Test instantiating viewer."""\n    # Check only keybinding is Viewer\n    assert len(qt_viewer._key_map_handler.keymap_providers) == 1\n    assert qt_viewer._key_map_handler.keymap_providers[0] == viewer_model\n\n    # Add a layer and check it is keybindings are active\n    data = np.random.default_rng(0).random((10, 15))\n    layer_image = viewer_model.add_image(data)\n    assert viewer_model.layers.selection.active == layer_image\n    assert len(qt_viewer._key_map_handler.keymap_providers) == 2\n    assert qt_viewer._key_map_handler.keymap_providers[0] == layer_image\n\n    # Add a layer and check it is keybindings become active\n    layer_image_2 = viewer_model.add_image(data)\n    assert viewer_model.layers.selection.active == layer_image_2\n    assert len(qt_viewer._key_map_handler.keymap_providers) == 2\n    assert qt_viewer._key_map_handler.keymap_providers[0] == layer_image_2\n\n    # Change active layer and check it is keybindings become active\n    viewer_model.layers.selection.active = layer_image\n    assert viewer_model.layers.selection.active == layer_image\n    assert len(qt_viewer._key_map_handler.keymap_providers) == 2\n    assert qt_viewer._key_map_handler.keymap_providers[0] == layer_image\n\n\ndef test_process_mouse_event(\n    qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    """Test that the correct properties are added to the\n    MouseEvent by _process_mouse_events.\n    """\n    # make a mock mouse event\n    new_pos = (25, 25)\n    mouse_event = MouseEvent(\n        type=\'mouse_press\',\n        pos=new_pos,\n    )\n    data = np.zeros((5, 20, 20, 20), dtype=int)\n    data[1, 0:10, 0:10, 0:10] = 1\n\n    labels = viewer_model.add_labels(\n        data, scale=(1, 2, 1, 1), translate=(5, 5, 5)\n    )\n\n    @labels.mouse_drag_callbacks.append\n    def on_click(layer, event):\n        np.testing.assert_almost_equal(event.view_direction, [0, -1, 0, 0])\n        np.testing.assert_array_equal(event.dims_displayed, [1, 2, 3])\n        assert event.dims_point[0] == data.shape[0] // 2\n\n        expected_position = qt_viewer.canvas._map_canvas2world(\n            new_pos, qt_viewer.canvas.view\n        )\n        np.testing.assert_almost_equal(expected_position, list(event.position))\n\n    viewer_model.dims.ndisplay = 3\n    qt_viewer.canvas._process_mouse_event(mouse_press_callbacks, mouse_event)\n\n\ndef test_process_mouse_event_2d_layer_3d_viewer(\n    qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    """Test that _process_mouse_events can handle 2d layers in 3D.\n\n    This is a test for: https://github.com/napari/napari/issues/7299\n    """\n\n    # make a mock mouse event\n    new_pos = (5, 5)\n    mouse_event = MouseEvent(\n        type=\'mouse_press\',\n        pos=new_pos,\n    )\n    data = np.zeros((20, 20))\n\n    image = viewer_model.add_image(data)\n\n    @image.mouse_drag_callbacks.append\n    def on_click(layer, event):\n        expected_position = qt_viewer.canvas._map_canvas2world(\n            new_pos, qt_viewer.canvas.view\n        )\n        np.testing.assert_almost_equal(expected_position, list(event.position))\n\n    assert viewer_model.dims.ndisplay == 2\n    qt_viewer.canvas._process_mouse_event(mouse_press_callbacks, mouse_event)\n\n    viewer_model.dims.ndisplay = 3\n    qt_viewer.canvas._process_mouse_event(mouse_press_callbacks, mouse_event)\n\n\n@pytest.mark.usefixtures(\n    \'qt_viewer\'\n)  # need qt_viewer to trigger the vispy code\ndef test_remove_points(viewer_model: ViewerModel) -> None:\n    viewer_model.add_points([(1, 2), (2, 3)])\n    del viewer_model.layers[0]\n    viewer_model.add_points([(1, 2), (2, 3)])\n\n\n@pytest.mark.usefixtures(\n    \'qt_viewer\'\n)  # need qt_viewer to trigger the vispy code\ndef test_remove_image(viewer_model: ViewerModel) -> None:\n    rng = np.random.default_rng(0)\n    viewer_model.add_image(rng.random((10, 10)))\n    del viewer_model.layers[0]\n    viewer_model.add_image(rng.random((10, 10)))\n\n\n@pytest.mark.usefixtures(\n    \'qt_viewer\'\n)  # need qt_viewer to trigger the vispy code\ndef test_remove_labels(viewer_model: ViewerModel) -> None:\n    rng = np.random.default_rng(0)\n    viewer_model.add_labels(rng.integers(0, 10, size=(10, 10), dtype=np.int8))\n    del viewer_model.layers[0]\n    viewer_model.add_labels(rng.integers(0, 10, size=(10, 10), dtype=np.int8))\n\n\n@pytest.mark.skip(\n    reason=\'Broadcasting layers is broken by reordering dims, see #3882\'\n)\n@pytest.mark.parametrize(\'multiscale\', [False, True])\ndef test_mixed_2d_and_3d_layers(\n    viewer_model: ViewerModel, qt_viewer: QtViewer, multiscale: bool\n) -> None:\n    """Test bug in setting corner_pixels from qt_viewer.on_draw"""\n    img = np.ones((512, 256))\n    # canvas size must be large enough that img fits in the canvas\n    canvas_size = tuple(3 * s for s in img.shape)\n    expected_corner_pixels = np.asarray([[0, 0], [s - 1 for s in img.shape]])\n\n    vol = np.stack([img] * 8, axis=0)\n    if multiscale:\n        img = [img[::s, ::s] for s in (1, 2, 4)]\n    viewer_model.add_image(img)\n    img_multi_layer = viewer_model.layers[0]\n    viewer_model.add_image(vol)\n\n    viewer_model.dims.order = (0, 1, 2)\n    qt_viewer.canvas.size = canvas_size\n    qt_viewer.canvas.on_draw(None)\n    np.testing.assert_array_equal(\n        img_multi_layer.corner_pixels, expected_corner_pixels\n    )\n\n    viewer_model.dims.order = (2, 0, 1)\n    qt_viewer.canvas.on_draw(None)\n    np.testing.assert_array_equal(\n        img_multi_layer.corner_pixels, expected_corner_pixels\n    )\n\n    viewer_model.dims.order = (1, 2, 0)\n    qt_viewer.canvas.on_draw(None)\n    np.testing.assert_array_equal(\n        img_multi_layer.corner_pixels, expected_corner_pixels\n    )\n\n\n@pytest.mark.usefixtures(\n    \'qt_viewer\'\n)  # need qt_viewer to trigger the vispy code\ndef test_remove_add_image_3D(viewer_model: ViewerModel) -> None:\n    """\n    Test that adding, removing and readding an image layer in 3D does not cause issues\n    due to the vispy node change. See https://github.com/napari/napari/pull/3670\n    """\n    viewer_model.dims.ndisplay = 3\n    img = np.ones((10, 10, 10))\n\n    layer = viewer_model.add_image(img)\n    viewer_model.layers.remove(layer)\n    viewer_model.layers.append(layer)\n\n\n@skip_on_win_ci\n@skip_local_popups\n@pytest.mark.show_qt_viewer\ndef test_qt_viewer_multscale_image_out_of_view(viewer_model):\n    """Test out-of-view multiscale image viewing fix.\n\n    Just verifies that no RuntimeError is raised in this scenario.\n\n    see: https://github.com/napari/napari/issues/3863.\n    """\n    # show=True required to test fix for OpenGL error\n    viewer_model.dims.ndisplay = 2\n    viewer_model.add_shapes(\n        data=[\n            np.array(\n                [[1500, 4500], [4500, 4500], [4500, 1500], [1500, 1500]],\n                dtype=float,\n            )\n        ],\n        shape_type=[\'polygon\'],\n    )\n    viewer_model.add_image([np.eye(1024), np.eye(512), np.eye(256)])\n\n\ndef test_insert_layer_ordering(\n    viewer_model: ViewerModel, qt_viewer: QtViewer\n) -> None:\n    """make sure layer ordering is correct in vispy when inserting layers"""\n    pl1 = Points()\n    pl2 = Points()\n\n    viewer_model.layers.append(pl1)\n    viewer_model.layers.insert(0, pl2)\n\n    pl1_vispy = qt_viewer.canvas.layer_to_visual[pl1].node\n    pl2_vispy = qt_viewer.canvas.layer_to_visual[pl2].node\n    assert pl1_vispy.order == 1\n    assert pl2_vispy.order == 0\n\n\ndef test_create_non_empty_viewer_model(qtbot: QtBot) -> None:\n    viewer_model = ViewerModel()\n    viewer_model.add_points([(1, 2), (2, 3)])\n\n    viewer = QtViewer(viewer=viewer_model)\n\n    viewer.close()\n    viewer.deleteLater()\n    # try to del local reference for gc.\n    del viewer_model\n    del viewer\n    qtbot.wait(50)\n    gc.collect()\n\n\ndef _update_data(\n    layer: Labels,\n    label: int,\n    qtbot: QtBot,\n    qt_viewer: QtViewer,\n    dtype: np.dtype = np.uint64,\n) -> tuple[np.ndarray, np.ndarray]:\n    """Change layer data and return color of label and middle pixel of screenshot."""\n    layer.data = np.full((2, 2), label, dtype=dtype)\n    layer.selected_label = label\n\n    qtbot.wait(50)  # wait for .update() to be called on QtColorBox from Qt\n\n    color_box_color = qt_viewer.controls.widgets[\n        layer\n    ]._label_control.colorbox.color\n    screenshot = qt_viewer.screenshot(flash=False)\n    shape = np.array(screenshot.shape[:2])\n    middle_pixel = screenshot[tuple(shape // 2)]\n\n    return color_box_color, middle_pixel\n\n\n@pytest.fixture\ndef qt_viewer_with_controls(qt_viewer: QtViewer) -> QtViewer:\n    qt_viewer.controls.show()\n    return qt_viewer\n\n\n@skip_local_popups\n@skip_on_win_ci\n@pytest.mark.parametrize(\n    \'use_selection\', [True, False], ids=[\'selected\', \'all\']\n)\n@pytest.mark.parametrize(\'dtype\', [np.int8, np.int16, np.int64])\n@pytest.mark.show_qt_viewer\ndef test_label_colors_matching_widget_auto(\n    qtbot: QtBot,\n    qt_viewer_with_controls: QtViewer,\n    use_selection: bool,\n    dtype: np.dtype,\n) -> None:\n    """Make sure the rendered label colors match the QtColorBox widget."""\n\n    rng = np.random.default_rng(0)\n    data = np.ones((2, 2), dtype=dtype)\n    layer = qt_viewer_with_controls.viewer.add_labels(data)\n    layer.show_selected_label = use_selection\n    layer.opacity = 1.0  # QtColorBox & single layer are blending differently\n    n_c = len(layer.colormap)\n\n    test_colors = np.concatenate(\n        (\n            np.arange(1, 10, dtype=dtype),\n            [n_c - 1, n_c, n_c + 1],\n            rng.integers(\n                1, min(2**20, np.iinfo(dtype).max), size=20, dtype=dtype\n            ),\n            [-1, -2, -10],\n        )\n    )\n\n    for label in test_colors:\n        # Change color & selected color to the same label\n        color_box_color, middle_pixel = _update_data(\n            layer, label, qtbot, qt_viewer_with_controls, dtype\n        )\n\n        npt.assert_allclose(\n            color_box_color, middle_pixel, atol=1, err_msg=f\'label {label}\'\n        )\n        # there is a difference of rounding between the QtColorBox and the screenshot\n\n\n@skip_local_popups\n@skip_on_win_ci\n@pytest.mark.parametrize(\n    \'use_selection\', [True, False], ids=[\'selected\', \'all\']\n)\n@pytest.mark.parametrize(\'dtype\', [np.uint64, np.uint16, np.uint8, np.int16])\n@pytest.mark.show_qt_viewer\ndef test_label_colors_matching_widget_direct(\n    qtbot: QtBot,\n    qt_viewer_with_controls: QtViewer,\n    use_selection: bool,\n    dtype: np.dtype,\n):\n    """Make sure the rendered label colors match the QtColorBox widget."""\n    data = np.ones((2, 2), dtype=dtype)\n\n    test_colors = (1, 2, 3, 8, 150, 50)\n    color = {\n        0: \'transparent\',\n        1: \'yellow\',\n        3: \'blue\',\n        8: \'red\',\n        150: \'green\',\n        None: \'white\',\n    }\n    if np.iinfo(dtype).min < 0:\n        color[-1] = \'pink\'\n        color[-2] = \'orange\'\n        test_colors = test_colors + (-1, -2, -10)\n\n    colormap = DirectLabelColormap(color_dict=color)\n    layer = qt_viewer_with_controls.viewer.add_labels(\n        data, opacity=1, colormap=colormap\n    )\n    layer.show_selected_label = use_selection\n\n    color_box_color, middle_pixel = _update_data(\n        layer, 0, qtbot, qt_viewer_with_controls, dtype\n    )\n    assert np.allclose([0, 0, 0, 255], middle_pixel)\n\n    for label in test_colors:\n        # Change color & selected color to the same label\n        color_box_color, middle_pixel = _update_data(\n            layer, label, qtbot, qt_viewer_with_controls, dtype\n        )\n        npt.assert_almost_equal(\n            color_box_color, middle_pixel, err_msg=f\'{label=}\'\n        )\n        npt.assert_almost_equal(\n            color_box_color,\n            colormap.color_dict.get(label, colormap.color_dict[None]) * 255,\n            err_msg=f\'{label=}\',\n        )\n\n\ndef test_axis_labels(viewer_model: ViewerModel, qt_viewer: QtViewer) -> None:\n    viewer_model.dims.ndisplay = 3\n    viewer_model.axes.visible = True\n\n    layer = viewer_model.add_image(np.zeros((2, 2, 2)), scale=(1, 2, 4))\n\n    layer_visual = qt_viewer.layer_to_visual[layer]\n    axes_visual = qt_viewer.canvas._overlay_to_visual[\n        viewer_model._overlays[\'axes\']\n    ][0]\n\n    layer_visual_size = vispy_image_scene_size(layer_visual)\n    assert tuple(layer_visual_size) == (8, 4, 2)\n    assert tuple(axes_visual.node.text.text) == (\'-1\', \'-2\', \'-3\')\n\n\ndef _find_margin(data: np.ndarray, additional_margin: int) -> tuple[int, int]:\n    """\n    helper function to determine margins in test_thumbnail_labels\n    """\n\n    mid_x, mid_y = data.shape[0] // 2, data.shape[1] // 2\n    x_margin = len(\n        list(takewhile(lambda x: np.all(x == 0), data[:, mid_y, :3][::-1]))\n    )\n    y_margin = len(\n        list(takewhile(lambda x: np.all(x == 0), data[mid_x, :, :3][::-1]))\n    )\n    return x_margin + additional_margin, y_margin + additional_margin\n\n\n# @pytest.mark.xfail(reason="Fails on CI, but not locally")\n@skip_local_popups\n@pytest.mark.show_qt_viewer\n@pytest.mark.parametrize(\'direct\', [True, False], ids=[\'direct\', \'auto\'])\ndef test_thumbnail_labels(\n    qtbot: QtBot, direct: bool, qt_viewer: QtViewer, tmp_path: Path\n) -> None:\n    # Add labels to empty viewer\n    layer = qt_viewer.viewer.add_labels(\n        np.array([[0, 1], [2, 3]]), opacity=1.0\n    )\n    if direct:\n        layer.colormap = DirectLabelColormap(\n            color_dict={\n                0: \'red\',\n                1: \'green\',\n                2: \'blue\',\n                3: \'yellow\',\n                None: \'black\',\n            }\n        )\n    else:\n        layer.colormap = label_colormap(49)\n    qt_viewer.viewer.reset_view()\n    qt_viewer.canvas.native.paintGL()\n    QApplication.processEvents()\n    qtbot.wait(50)\n\n    canvas_screenshot_ = qt_viewer.screenshot(flash=False)\n\n    import imageio\n\n    imageio.imwrite(tmp_path / \'canvas_screenshot_.png\', canvas_screenshot_)\n    np.savez(tmp_path / \'canvas_screenshot_.npz\', canvas_screenshot_)\n\n    # cut off black border\n    margin1, margin2 = _find_margin(canvas_screenshot_, 10)\n    canvas_screenshot = canvas_screenshot_[margin1:-margin1, margin2:-margin2]\n    assert canvas_screenshot.size > 0, (\n        f\'{canvas_screenshot_.shape}, {margin1=}, {margin2=}\'\n    )\n\n    thumbnail = layer.thumbnail\n    scaled_thumbnail = ndi.zoom(\n        thumbnail,\n        np.array(canvas_screenshot.shape) / np.array(thumbnail.shape),\n        order=0,\n        mode=\'nearest\',\n    )\n    close = np.isclose(canvas_screenshot, scaled_thumbnail)\n    problematic_pixels_count = np.sum(~close)\n    assert problematic_pixels_count < 0.01 * canvas_screenshot.size\n\n\n@pytest.mark.show_qt_viewer\n@pytest.mark.parametrize(\'dtype\', [np.int8, np.int16, np.int32])\ndef test_background_color(\n    qtbot: QtBot, qt_viewer: QtViewer, dtype: np.dtype\n) -> None:\n    data = np.zeros((10, 10), dtype=dtype)\n    data[5:] = 10\n    layer = qt_viewer.viewer.add_labels(data, opacity=1)\n    color = layer.colormap.map(10) * 255\n\n    backgrounds = (0, 2, -2)\n\n    for background in backgrounds:\n        data[:5] = background\n        layer.data = data\n        layer.colormap = label_colormap(49, background_value=background)\n        qtbot.wait(50)\n        canvas_screenshot = qt_viewer.screenshot(flash=False)\n        shape = np.array(canvas_screenshot.shape[:2])\n        background_pixel = canvas_screenshot[tuple((shape * 0.25).astype(int))]\n        color_pixel = canvas_screenshot[tuple((shape * 0.75).astype(int))]\n        npt.assert_array_equal(\n            background_pixel,\n            [0, 0, 0, 255],\n            err_msg=f\'background {background}\',\n        )\n        npt.assert_array_equal(\n            color_pixel, color, err_msg=f\'background {background}\'\n        )\n\n\n@pytest.mark.show_qt_viewer\ndef test_rendering_interpolation(\n    qtbot: QtBot, qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    data = np.zeros((20, 20, 20), dtype=np.uint8)\n    data[1:-1, 1:-1, 1:-1] = 5\n    layer = viewer_model.add_labels(data, opacity=1, rendering=\'translucent\')\n    layer.selected_label = 5\n    viewer_model.dims.ndisplay = 3\n    QApplication.processEvents()\n    canvas_screenshot = qt_viewer.screenshot(flash=False)\n    shape = np.array(canvas_screenshot.shape[:2])\n    pixel = canvas_screenshot[tuple((shape * 0.5).astype(int))]\n    color = layer.colormap.map(5) * 255\n    npt.assert_array_equal(pixel, color)\n\n\n@pytest.mark.slow\n@pytest.mark.show_qt_viewer\n@pytest.mark.parametrize(\'mode\', [\'direct\', \'random\'])\ndef test_selection_collision(\n    qt_viewer: QtViewer,\n    viewer_model: ViewerModel,\n    mode: typing.Literal[\'direct\', \'random\'],\n) -> None:\n    data = np.zeros((10, 10), dtype=np.uint8)\n    data[:5] = 10\n    data[5:] = 10 + 49\n    layer = viewer_model.add_labels(data, opacity=1)\n    layer.selected_label = 10\n    if mode == \'direct\':\n        layer.colormap = DirectLabelColormap(\n            color_dict={10: \'red\', 10 + 49: \'red\', None: \'black\'}\n        )\n\n    for dtype in NUMPY_INTEGER_TYPES:\n        layer.data = data.astype(dtype)\n        layer.show_selected_label = False\n        QApplication.processEvents()\n        canvas_screenshot = qt_viewer.screenshot(flash=False)\n        shape = np.array(canvas_screenshot.shape[:2])\n        pixel_10 = canvas_screenshot[tuple((shape * 0.25).astype(int))]\n        pixel_59 = canvas_screenshot[tuple((shape * 0.75).astype(int))]\n        npt.assert_array_equal(pixel_10, pixel_59, err_msg=f\'{dtype}\')\n        assert not np.all(pixel_10 == [0, 0, 0, 255]), dtype\n\n        layer.show_selected_label = True\n\n        canvas_screenshot = qt_viewer.screenshot(flash=False)\n        shape = np.array(canvas_screenshot.shape[:2])\n        pixel_10_2 = canvas_screenshot[tuple((shape * 0.25).astype(int))]\n        pixel_59_2 = canvas_screenshot[tuple((shape * 0.75).astype(int))]\n\n        npt.assert_array_equal(pixel_59_2, [0, 0, 0, 255], err_msg=f\'{dtype}\')\n        npt.assert_array_equal(pixel_10_2, pixel_10, err_msg=f\'{dtype}\')\n\n\n@pytest.mark.show_qt_viewer\ndef test_all_supported_dtypes(\n    qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    data = np.zeros((10, 10), dtype=np.uint8)\n    layer_ = viewer_model.add_labels(data, opacity=1)\n\n    for i, dtype in enumerate(NUMPY_INTEGER_TYPES, start=1):\n        data = np.full((10, 10), i, dtype=dtype)\n        layer_.data = data\n        QApplication.processEvents()\n        canvas_screenshot = qt_viewer.screenshot(flash=False)\n        midd_pixel = canvas_screenshot[\n            tuple(np.array(canvas_screenshot.shape[:2]) // 2)\n        ]\n        npt.assert_equal(\n            midd_pixel, layer_.colormap.map(i) * 255, err_msg=f\'{dtype=} {i=}\'\n        )\n\n    layer_.colormap = DirectLabelColormap(\n        color_dict={\n            0: \'red\',\n            1: \'green\',\n            2: \'blue\',\n            3: \'yellow\',\n            4: \'magenta\',\n            5: \'cyan\',\n            6: \'white\',\n            7: \'pink\',\n            8: \'orange\',\n            9: \'purple\',\n            10: \'brown\',\n            11: \'gray\',\n            None: \'black\',\n        }\n    )\n\n    for i, dtype in enumerate(NUMPY_INTEGER_TYPES, start=1):\n        data = np.full((10, 10), i, dtype=dtype)\n        layer_.data = data\n        QApplication.processEvents()\n        canvas_screenshot = qt_viewer.screenshot(flash=False)\n        midd_pixel = canvas_screenshot[\n            tuple(np.array(canvas_screenshot.shape[:2]) // 2)\n        ]\n        npt.assert_equal(\n            midd_pixel, layer_.colormap.map(i) * 255, err_msg=f\'{dtype} {i}\'\n        )\n\n\n@pytest.mark.slow\n@pytest.mark.show_qt_viewer\ndef test_more_than_uint16_colors(\n    qt_viewer: QtViewer, viewer_model: ViewerModel\n) -> None:\n    pytest.importorskip(\'numba\')\n    # this test is slow (10s locally)\n    data = np.zeros((10, 10), dtype=np.uint32)\n    colors = {\n        i: (x, y, z, 1)\n        for i, (x, y, z) in zip(\n            range(256**2 + 20),\n            product(np.linspace(0, 1, 256, endpoint=True), repeat=3),\n            strict=False,\n        )\n    }\n    colors[None] = (0, 0, 0, 1)\n    layer = viewer_model.add_labels(\n        data, opacity=1, colormap=DirectLabelColormap(color_dict=colors)\n    )\n    assert layer._slice.image.view.dtype == np.float32\n\n    for i in [1, 1000, 100000]:\n        data = np.full((10, 10), i, dtype=np.uint32)\n        layer.data = data\n        canvas_screenshot = qt_viewer.screenshot(flash=False)\n        midd_pixel = canvas_screenshot[\n            tuple(np.array(canvas_screenshot.shape[:2]) // 2)\n        ]\n        npt.assert_equal(\n            midd_pixel, layer.colormap.map(i) * 255, err_msg=f\'{i}\'\n        )\n\n\n@skip_local_popups\n@pytest.mark.show_qt_viewer\ndef test_scale_bar_colored(\n    qt_viewer: QtViewer, viewer_model: ViewerModel, qtbot\n) -> None:\n    scale_bar = viewer_model.scale_bar\n\n    # Add black image\n    data = np.zeros((2, 2))\n    viewer_model.add_image(data)\n\n    # Check scale bar is not visible (all the canvas is black - `[0, 0, 0, 255]`)\n    def check_all_black():\n        screenshot = qt_viewer.screenshot(flash=False)\n        assert np.all(screenshot == [0, 0, 0, 255], axis=-1).all()\n\n    qtbot.waitUntil(check_all_black)\n\n    # Check scale bar is visible (canvas has white `[1, 1, 1, 255]` in it)\n    def check_white_scale_bar():\n        screenshot = qt_viewer.screenshot(flash=False)\n        assert not np.all(screenshot == [0, 0, 0, 255], axis=-1).all()\n        # antialiasing can make things less saturated\n        assert np.all(screenshot[..., 0] == screenshot[..., 1])\n        assert np.all(screenshot[..., 1] == screenshot[..., 2])\n\n    scale_bar.visible = True\n    qtbot.waitUntil(check_white_scale_bar)\n\n    # Check scale bar is colored (canvas has fuchsia `[1, 0, 1, 255]` and not white in it)\n    def check_colored_scale_bar():\n        screenshot = qt_viewer.screenshot(flash=False)\n        assert not np.all(screenshot == [0, 0, 0, 255], axis=-1).all()\n        # antialiasing can make things less saturated\n        assert np.all(screenshot[..., 0] == screenshot[..., 2])\n        assert np.all(screenshot[..., 1] == 0)\n\n    scale_bar.colored = True\n    qtbot.waitUntil(check_colored_scale_bar)\n\n    # Check scale bar is still visible but not colored (canvas has white again but not fuchsia in it)\n    def check_only_white_scale_bar():\n        screenshot = qt_viewer.screenshot(flash=False)\n        assert not np.all(screenshot == [0, 0, 0, 255], axis=-1).all()\n        # antialiasing can make things less saturated\n        assert np.all(screenshot[..., 0] == screenshot[..., 1])\n        assert np.all(screenshot[..., 1] == screenshot[..., 2])\n\n    scale_bar.colored = False\n    qtbot.waitUntil(check_only_white_scale_bar)\n\n\n@skip_local_popups\n@pytest.mark.show_qt_viewer\ndef test_scale_bar_ticks(\n    qt_viewer: QtViewer, viewer_model: ViewerModel, qtbot\n) -> None:\n    scale_bar = viewer_model.scale_bar\n\n    # Add black image\n    data = np.zeros((2, 2))\n    viewer_model.add_image(data)\n\n    # Check scale bar is not visible (all the canvas is black - `[0, 0, 0, 255]`)\n    def check_all_black():\n        screenshot = qt_viewer.screenshot(flash=False)\n        assert np.all(screenshot == [0, 0, 0, 255], axis=-1).all()\n\n    qtbot.waitUntil(check_all_black)\n\n    # Check scale bar is visible (canvas has white `[1, 1, 1, 255]` in it)\n    def check_white_scale_bar():\n        screenshot = qt_viewer.screenshot(flash=False)\n        assert not np.all(screenshot == [0, 0, 0, 255], axis=-1).all()\n        # antialiasing can make things less saturated\n        assert np.all(screenshot[..., 0] == screenshot[..., 1])\n        assert np.all(screenshot[..., 1] == screenshot[..., 2])\n\n    scale_bar.visible = True\n    qtbot.waitUntil(check_white_scale_bar)\n\n    # Check scale bar has ticks active and take screenshot for later comparison\n    assert scale_bar.ticks\n    screenshot_with_ticks = qt_viewer.screenshot(flash=False)\n\n    # Check scale bar without ticks (still white present but new screenshot differs from ticks one)\n    def check_no_ticks_scale_bar():\n        screenshot = qt_viewer.screenshot(flash=False)\n        # antialiasing can make things less saturated\n        assert np.all(screenshot[..., 0] == screenshot[..., 1])\n        assert np.all(screenshot[..., 1] == screenshot[..., 2])\n        npt.assert_raises(\n            AssertionError,\n            npt.assert_array_equal,\n            screenshot,\n            screenshot_with_ticks,\n        )\n\n    scale_bar.ticks = False\n    qtbot.waitUntil(check_no_ticks_scale_bar)\n\n    # Check scale bar again has ticks (still white present and new screenshot corresponds with ticks one)\n    def check_ticks_scale_bar():\n        screenshot = qt_viewer.screenshot(flash=False)\n        # antialiasing can make things less saturated\n        assert np.all(screenshot[..., 0] == screenshot[..., 1])\n        assert np.all(screenshot[..., 1] == screenshot[..., 2])\n        # some variation can happen with antialiasing\n        npt.assert_allclose(screenshot, screenshot_with_ticks, atol=1)\n\n    scale_bar.ticks = True\n    qtbot.waitUntil(check_ticks_scale_bar)\n\n\n@skip_local_popups\n@pytest.mark.usefixtures(\'qt_viewer\')\ndef test_dask_cache():\n    initial_dask_cache = get_settings().application.dask.cache\n\n    # check that disabling dask cache setting calls related logic\n    with mock.patch(\n        \'napari._qt.qt_viewer.resize_dask_cache\'\n    ) as mock_resize_dask_cache:\n        get_settings().application.dask.enabled = False\n    mock_resize_dask_cache.assert_called_once_with(\n        int(int(False) * initial_dask_cache * 1e9)\n    )\n\n    # check that enabling dask cache setting calls related logic\n    with mock.patch(\n        \'napari._qt.qt_viewer.resize_dask_cache\'\n    ) as mock_resize_dask_cache:\n        get_settings().application.dask.enabled = True\n    mock_resize_dask_cache.assert_called_once_with(\n        int(int(True) * initial_dask_cache * 1e9)\n    )\n\n\n@pytest.mark.show_qt_viewer\ndef test_viewer_drag_to_zoom(\n    qt_viewer: QtViewer, viewer_model: ViewerModel, qtbot: QtBot\n) -> None:\n    """Test drag to zoom mouse binding."""\n    canvas = qt_viewer.canvas\n\n    def zoom_callback(data_positions):\n        """Mock zoom callback to check zoom box visibility."""\n        assert len(data_positions) == 2, (\n            \'Zoom event should release two positions\'\n        )\n\n    zoom_area_mock = mock.Mock(side_effect=zoom_callback)\n\n    viewer_model._zoom_box.events.zoom_area.connect(zoom_area_mock)\n\n    # Add an image layer\n    data = np.random.default_rng(0).random((10, 20))\n    viewer_model.add_image(data)\n\n    assert viewer_model._zoom_box.visible is False, (\n        \'Zoom box should be hidden initially\'\n    )\n    qtbot.wait(10)\n    # Simulate press to start zooming\n    canvas._scene_canvas.events.mouse_press(\n        pos=(0, 0), modifiers=(\'Alt\',), button=0\n    )\n    qtbot.wait(10)\n    assert viewer_model._zoom_box.visible is True, (\n        \'Zoom box should be visible after press\'\n    )\n\n    # Simulate drag to zoom\n    canvas._scene_canvas.events.mouse_move(\n        pos=(100, 100),\n        modifiers=(\'Alt\',),\n        button=0,\n        press_event=MouseEvent(\n            pos=(0, 0), modifiers=(\'Alt\',), button=0, type=\'mouse_press\'\n        ),\n    )\n    qtbot.wait(10)\n    assert viewer_model._zoom_box.visible is True, (\n        \'Zoom box should remain visible during drag\'\n    )\n    assert viewer_model._zoom_box.position == ((0, 0), (100, 100)), (\n        \'Zoom box canvas positions should match the drag coordinates\'\n    )\n\n    # Simulate release to finish zooming\n    canvas._scene_canvas.events.mouse_release(\n        pos=(100, 100), modifiers=(\'Alt\',), button=0\n    )\n    qtbot.wait(10)\n    assert viewer_model._zoom_box.visible is False, (\n        \'Zoom box should be hidden after release\'\n    )\n\n    assert zoom_area_mock.call_count == 1\n\n\n@pytest.mark.show_qt_viewer\ndef test_viewer_drag_to_zoom_with_cancel(\n    qt_viewer: QtViewer, viewer_model: ViewerModel, qtbot: QtBot\n) -> None:\n    """Test drag to zoom mouse binding."""\n    canvas = qt_viewer.canvas\n\n    zoom_area_mock = mock.Mock()\n\n    viewer_model._zoom_box.events.zoom_area.connect(zoom_area_mock)\n\n    # Add an image layer\n    data = np.random.default_rng(0).random((10, 20))\n    viewer_model.add_image(data)\n\n    assert viewer_model._zoom_box.visible is False, (\n        \'Zoom box should be hidden initially\'\n    )\n    qtbot.wait(10)\n    # Simulate press to start zooming\n    canvas._scene_canvas.events.mouse_press(\n        pos=(0, 0), modifiers=(\'Alt\',), button=0\n    )\n    qtbot.wait(10)\n    assert viewer_model._zoom_box.visible is True, (\n        \'Zoom box should be visible after press\'\n    )\n\n    # Simulate drag to zoom BUT remove modifiers to cancel\n    canvas._scene_canvas.events.mouse_move(\n        pos=(100, 100),\n        modifiers=(),\n        button=0,\n        press_event=MouseEvent(\n            pos=(0, 0), modifiers=(\'Alt\',), button=0, type=\'mouse_press\'\n        ),\n    )\n    qtbot.wait(10)\n    assert viewer_model._zoom_box.visible is False, (\n        \'Zoom box should remain visible during drag\'\n    )\n    assert viewer_model._zoom_box.position == ((0, 0), (0, 0)), (\n        \'Zoom box canvas positions should match the drag coordinates\'\n    )\n    zoom_area_mock.assert_not_called()\n',
            'src/napari/_vispy/_tests/test_canvas.py': "import numpy as np\n\nfrom napari.components.overlays import (\n    BoundingBoxOverlay,\n    CanvasOverlay,\n    ScaleBarOverlay,\n)\n\n\ndef test_viewer_overlays(qt_viewer):\n    viewer = qt_viewer.viewer\n    canvas = qt_viewer.canvas\n\n    for overlay in viewer._overlays.values():\n        # vispy overlays only exist if they are visible at least once\n        overlay.visible = True\n        if isinstance(overlay, CanvasOverlay):\n            assert all(\n                visual.node in canvas.view.children\n                for visual in canvas._overlay_to_visual[overlay]\n            )\n        else:\n            assert all(\n                visual.node in canvas.view.scene.children\n                for visual in canvas._overlay_to_visual[overlay]\n            )\n\n    old_vispy_overlays = {\n        k: list(v) for k, v in canvas._overlay_to_visual.items()\n    }\n\n    new_overlay = ScaleBarOverlay(visible=True)\n    viewer._overlays['test'] = new_overlay\n\n    assert new_overlay in canvas._overlay_to_visual\n    new_overlay_node = canvas._overlay_to_visual[new_overlay][0].node\n    assert new_overlay_node not in canvas.view.scene.children\n    assert new_overlay_node in canvas.view.children\n\n    # old visuals should still be there, as they are reused when possible\n    for overlay, vispy_overlays in old_vispy_overlays.items():\n        for vispy_overlay in vispy_overlays:\n            if isinstance(overlay, CanvasOverlay):\n                assert vispy_overlay.node in canvas.view.children\n            else:\n                assert vispy_overlay.node in canvas.view.scene.children\n\n    viewer._overlays.pop('test')\n    assert new_overlay not in canvas._overlay_to_visual\n    assert new_overlay_node not in canvas.view.children\n\n    viewer.welcome_screen.visible = False  # just for proper test cleanup\n\n\ndef test_layer_overlays(qt_viewer):\n    viewer = qt_viewer.viewer\n    canvas = qt_viewer.canvas\n\n    view_children = len(canvas.view.children)\n    scene_children = len(canvas.view.scene.children)\n\n    assert not canvas._layer_overlay_to_visual\n\n    layer = viewer.add_points()\n    layer_node = canvas.layer_to_visual[layer].node\n\n    for overlay in layer._overlays.values():\n        # vispy overlays only exist if they are visible at least once\n        overlay.visible = True\n        if isinstance(overlay, CanvasOverlay):\n            assert (\n                canvas._layer_overlay_to_visual[layer][overlay].node\n                in canvas.view.children\n            )\n        else:\n            assert (\n                canvas._layer_overlay_to_visual[layer][overlay].node\n                in layer_node.children\n            )\n\n    old_vispy_overlays = {**canvas._layer_overlay_to_visual[layer]}\n\n    new_overlay = BoundingBoxOverlay(visible=True)\n    layer._overlays['test'] = new_overlay\n\n    assert new_overlay in canvas._layer_overlay_to_visual[layer]\n    new_overlay_node = canvas._layer_overlay_to_visual[layer][new_overlay].node\n    assert new_overlay_node in layer_node.children\n    assert new_overlay_node not in canvas.view.children\n\n    # old visuals should still be there, as they are reused when possible\n    for overlay, vispy_overlay in old_vispy_overlays.items():\n        if isinstance(overlay, CanvasOverlay):\n            assert vispy_overlay.node in canvas.view.children\n        else:\n            assert vispy_overlay.node in layer_node.children\n\n    layer._overlays.pop('test')\n    assert new_overlay not in canvas._layer_overlay_to_visual[layer]\n    assert new_overlay_node not in canvas.view.children\n\n    viewer.layers.pop()\n\n    # should be back to the status quo\n    assert not canvas._layer_overlay_to_visual\n    assert len(canvas.view.children) == view_children\n    assert len(canvas.view.scene.children) == scene_children\n\n\ndef test_grid_mode(qt_viewer):\n    viewer = qt_viewer.viewer\n    canvas = qt_viewer.canvas\n\n    viewer.dims.ndisplay = 3\n    viewer.add_image(np.ones((10, 10, 10)))\n\n    angles = 10, 20, 30  # just some nonzero stuff\n    zoom = 1\n    viewer.camera.angles = angles\n    viewer.camera.zoom = zoom\n\n    canvas.on_draw(None)\n\n    for camera in (canvas.camera, *canvas.grid_cameras):\n        np.testing.assert_allclose(camera.angles, angles)\n        assert camera.zoom == zoom\n\n    # ensure that switching to grid maintains zoom and angles\n    viewer.grid.enabled = True\n\n    canvas.on_draw(None)\n\n    for camera in (canvas.camera, *canvas.grid_cameras):\n        np.testing.assert_allclose(camera.angles, angles)\n        assert camera.zoom == zoom\n\n    viewer.grid.enabled = False\n\n    canvas.on_draw(None)\n\n    for camera in (canvas.camera, *canvas.grid_cameras):\n        np.testing.assert_allclose(camera.angles, angles)\n        assert camera.zoom == zoom\n\n\ndef test_tiling_canvas_overlays(qt_viewer):\n    viewer = qt_viewer.viewer\n    canvas = qt_viewer.canvas\n\n    viewer.scale_bar.visible = True\n    viewer.text_overlay.visible = True\n    viewer.text_overlay.text = 'test'\n    viewer.scale_bar.position = 'bottom_left'\n    viewer.text_overlay.position = 'bottom_left'\n\n    vispy_scale_bar = canvas._overlay_to_visual[viewer.scale_bar][0]\n    vispy_text_overlay = canvas._overlay_to_visual[viewer.text_overlay][0]\n\n    padding = 10.0  # currently hardcoded\n    y_max, x_max = canvas.size\n\n    scale_bar_y_size = vispy_scale_bar.y_size + padding\n    scale_bar_x_size = vispy_scale_bar.x_size + padding\n\n    text_overlay_y_size = vispy_text_overlay.y_size + padding\n    text_overlay_x_size = vispy_text_overlay.x_size + padding\n\n    # check vertical tiling works on the bottom right\n    viewer.scale_bar.position = 'bottom_right'\n    viewer.text_overlay.position = 'bottom_right'\n    canvas._update_overlay_canvas_positions()\n\n    np.testing.assert_almost_equal(\n        vispy_text_overlay.node.transform.translate[0],\n        x_max - text_overlay_x_size,\n        decimal=3,\n    )\n    np.testing.assert_almost_equal(\n        vispy_text_overlay.node.transform.translate[1],\n        y_max - text_overlay_y_size - scale_bar_y_size,\n        decimal=3,\n    )\n\n    # move scale bar out of the way and check tiling is updated\n    viewer.scale_bar.position = 'top_right'\n    canvas._update_overlay_canvas_positions()\n    np.testing.assert_almost_equal(\n        vispy_text_overlay.node.transform.translate[0],\n        x_max - text_overlay_x_size,\n        decimal=3,\n    )\n    np.testing.assert_almost_equal(\n        vispy_text_overlay.node.transform.translate[1],\n        y_max - text_overlay_y_size,\n        decimal=3,\n    )\n\n    # check horizontal tiling works on the top right\n    viewer.text_overlay.position = 'top_right'\n    canvas._update_overlay_canvas_positions()\n    np.testing.assert_almost_equal(\n        vispy_text_overlay.node.transform.translate[0],\n        x_max - text_overlay_x_size - scale_bar_x_size,\n        decimal=3,\n    )\n    np.testing.assert_almost_equal(\n        vispy_text_overlay.node.transform.translate[1],\n        0 + padding,\n        decimal=3,\n    )\n",
            'src/napari/_vispy/canvas.py': '"""VispyCanvas class."""\n\nfrom __future__ import annotations\n\nimport contextlib\nimport gc\nfrom collections.abc import Iterator\nfrom functools import partial\nfrom itertools import zip_longest\nfrom types import MethodType\nfrom typing import TYPE_CHECKING\nfrom weakref import WeakSet\n\nimport numpy as np\nfrom OpenGL.error import GLError\nfrom superqt.utils import qthrottled\nfrom vispy.scene import Grid, SceneCanvas as SceneCanvas_, ViewBox, Widget\n\nfrom napari._vispy.camera import VispyCamera\nfrom napari._vispy.mouse_event import NapariMouseEvent\nfrom napari._vispy.utils.cursor import QtCursorVisual\nfrom napari._vispy.utils.gl import get_max_texture_sizes\nfrom napari._vispy.utils.qt_font import QtFontManager\nfrom napari._vispy.utils.visual import create_vispy_overlay\nfrom napari.components._viewer_constants import CanvasPosition\nfrom napari.components.overlays import CanvasOverlay\nfrom napari.utils._proxies import ReadOnlyWrapper\nfrom napari.utils.colormaps.standardize_color import transform_color\nfrom napari.utils.events import disconnect_events\nfrom napari.utils.events.event import Event\nfrom napari.utils.interactions import (\n    mouse_double_click_callbacks,\n    mouse_move_callbacks,\n    mouse_press_callbacks,\n    mouse_release_callbacks,\n    mouse_wheel_callbacks,\n)\nfrom napari.utils.notifications import show_warning\nfrom napari.utils.theme import get_theme\n\nif TYPE_CHECKING:\n    from collections.abc import Callable\n\n    import numpy.typing as npt\n    from qtpy.QtCore import Qt, pyqtBoundSignal\n    from qtpy.QtGui import QCursor, QImage\n    from vispy.app.backends._qt import CanvasBackendDesktop\n    from vispy.app.canvas import DrawEvent, MouseEvent, ResizeEvent\n    from vispy.scene import Node\n\n    from napari._vispy.layers.base import VispyBaseLayer\n    from napari._vispy.overlays.base import VispyBaseOverlay\n    from napari.components import ViewerModel\n    from napari.components.overlays import Overlay\n    from napari.layers import Layer\n    from napari.utils.key_bindings import KeymapHandler\n\n\nimport warnings\n\nfrom napari.utils.translations import trans\n\n\nclass NapariSceneCanvas(SceneCanvas_):\n    """Vispy SceneCanvas used to allow for ignoring mouse wheel events with modifiers."""\n\n    def __init__(self, *args, **kwargs):\n        super().__init__(*args, **kwargs)\n\n        orig_enterEvent = self.native.enterEvent\n        orig_leaveEvent = self.native.leaveEvent\n\n        def enterEvent(self_, event):\n            qtviewer = self_.parent()\n            qtviewer._enter_canvas()\n            orig_enterEvent(event)\n\n        def leaveEvent(self_, event):\n            qtviewer = self_.parent()\n            qtviewer._leave_canvas()\n            orig_leaveEvent(event)\n\n        self.native.enterEvent = MethodType(enterEvent, self.native)\n        self.native.leaveEvent = MethodType(leaveEvent, self.native)\n\n    def _process_mouse_event(self, event: MouseEvent):\n        """Ignore mouse wheel events which have modifiers."""\n        if event.type == \'mouse_wheel\' and len(event.modifiers) > 0:\n            return\n        if event.handled:\n            return\n        super()._process_mouse_event(event)\n\n    def draw_visual(self, visual, event=None):\n        try:\n            super().draw_visual(visual, event=event)\n        except RuntimeError as e:\n            error_msg = e.args[0] if e.args else \'\'\n            to_ignore = (\n                \'Cannot draw program if code has not been set\',\n                \'Cannot set uniform when program has no code\',\n            )\n            if any(msg in error_msg for msg in to_ignore):\n                # these always happens after another (real) error is raised, and\n                # they flood the traceback because they are fired on each event,\n                # hiding the actual source of the problem. They are never really\n                # informative, so we can safely ignore them.\n                return\n            if \'Shader compilation error\' in error_msg:\n                raise RuntimeError(\n                    \'Shader compilation failed. Unless you are working with custom shader code,\\n\'\n                    \'this is likely a bug in napari.\\n\'\n                    \'Please open an issue on the repository and provide this *full* stack trace.\'\n                ) from e\n            if \'Cannot SIZE object\' in error_msg:\n                raise RuntimeError(\n                    \'The above error may be caused by a version mismatch between vispy and napari.\\n\'\n                    \'Try recreating a fresh environment and reinstalling. If that does not work,\\n\'\n                    \'please open an issue on the repository and provide this *full* stack trace.\'\n                ) from e\n            raise\n\n\nclass VispyCanvas:\n    """Class for our QtViewer class to interact with Vispy SceneCanvas. Also\n    connects Vispy SceneCanvas events to the napari ViewerModel and vice versa.\n\n    Parameters\n    ----------\n    viewer : napari.components.ViewerModel\n        Napari viewer containing the rendered scene, layers, and controls.\n\n    Attributes\n    ----------\n    layer_to_visual : dict(napari.layers, napari._vispy.layers)\n        A mapping of the napari layers that have been added to the viewer and their corresponding vispy counterparts.\n    max_texture_sizes : Tuple[int, int]\n        The max textures sizes as a (2d, 3d) tuple.\n    viewer : napari.components.ViewerModel\n        Napari viewer containing the rendered scene, layers, and controls.\n    view : vispy.scene.widgets.viewbox.ViewBox\n        Rectangular widget in which a subscene is rendered.\n    camera : napari._vispy.VispyCamera\n        The camera class which contains both the 2d and 3d camera used to describe the perspective by which a\n        scene is viewed and interacted with.\n    _cursors : QtCursorVisual\n        A QtCursorVisual enum with as names the names of particular cursor styles and as value either a staticmethod\n        creating a bitmap or a Qt.CursorShape enum value corresponding to the particular cursor name. This enum only\n        contains cursors supported by Napari in Vispy.\n    _key_map_handler : napari.utils.key_bindings.KeymapHandler\n        KeymapHandler handling the calling functionality when keys are pressed that have a callback function mapped.\n    _last_theme_color : Optional[npt.NDArray[np.float]]\n        Theme color represented as numpy ndarray of shape (4,) before theme change\n        was applied.\n    _overlay_to_visual : dict(napari.components.overlays, list(napari._vispy.overlays))\n        A mapping of the napari overlays that are part of the viewer and their corresponding Vispy counterparts.\n        The values are lists that may contain multiple elements when grid mode is enabled and overlay.gridded == True,\n        associating multiple vispy visual to a single overlay model.\n    _layer_overlay_to_visual : dict(napari.layers.Layer, dict(napari.components.overlays, napari._vispy.overlays))\n        A mapping from each layer in the layerlist to their mappings of napari overlay->vispy counterpart.\n    _scene_canvas : napari._vispy.canvas.NapariSceneCanvas\n        SceneCanvas which automatically draws the contents of a scene. It is ultimately a VispySceneCanvas, but allows\n        for ignoring mousewheel events with modifiers.\n    """\n\n    _instances: WeakSet[VispyCanvas] = WeakSet()\n\n    def __init__(\n        self,\n        viewer: ViewerModel,\n        key_map_handler: KeymapHandler,\n        font_manager: QtFontManager,\n        font_family: str,\n        *args,\n        **kwargs,\n    ) -> None:\n        # Since the base class is frozen we must create this attribute\n        # before calling super().__init__().\n        self._pause_scene_graph = False\n        self.max_texture_sizes = None\n        self._last_theme_color = None\n        self._background_color_override = None\n        self._font_manager = font_manager\n        self._overlay_font = font_family\n        self.viewer = viewer\n        self._scene_canvas = NapariSceneCanvas(\n            *args, keys=None, vsync=True, **kwargs\n        )\n\n        self.view: ViewBox = self.central_widget.add_view(border_width=0)\n        self.view.order = 100  # ensure it\'s always drawn on top\n        self.camera = VispyCamera(\n            self.view, self.viewer.camera, self.viewer.dims\n        )\n\n        self.grid: Grid = self.central_widget.add_grid(\n            border_width=0,\n        )\n        self.grid_views = []\n        self.grid_cameras = []\n\n        self.layer_to_visual: dict[Layer, VispyBaseLayer[Layer]] = {}\n        self._overlay_to_visual: dict[Overlay, list[VispyBaseOverlay]] = {}\n        self._layer_overlay_to_visual: dict[\n            Layer, dict[Overlay, VispyBaseOverlay]\n        ] = {}\n        self._key_map_handler = key_map_handler\n        self._instances.add(self)\n\n        self._overlay_callbacks = {}\n        self._last_viewbox_size = np.array((0, 0))\n        self._needs_overlay_position_update = False\n        self._needs_world_units_update = False\n\n        self.bgcolor = transform_color(\n            get_theme(self.viewer.theme).canvas.as_hex()\n        )[0]\n\n        # Call get_max_texture_sizes() here so that we query OpenGL right\n        # now while we know a Canvas exists. Later calls to\n        # get_max_texture_sizes() will return the same results because it\'s\n        # using an lru_cache.\n        self.max_texture_sizes = get_max_texture_sizes()\n\n        self._update_grid_spacing()\n        self._update_viewer_overlays()\n\n        self._scene_canvas.events.ignore_callback_errors = False\n        self._scene_canvas.context.set_depth_func(\'lequal\')\n\n        self._scene_canvas.events.key_press.connect(\n            self._key_map_handler.on_key_press\n        )\n        self._scene_canvas.events.key_release.connect(\n            self._key_map_handler.on_key_release\n        )\n        self._scene_canvas.events.draw.connect(self.enable_dims_play)\n        self._scene_canvas.events.mouse_double_click.connect(\n            self._on_mouse_double_click\n        )\n        self._scene_canvas.events.mouse_move.connect(\n            qthrottled(self._on_mouse_move, timeout=5)\n        )\n        self._scene_canvas.events.mouse_press.connect(self._on_mouse_press)\n        self._scene_canvas.events.mouse_release.connect(self._on_mouse_release)\n        self._scene_canvas.events.mouse_wheel.connect(self._on_mouse_wheel)\n        self._scene_canvas.events.resize.connect(self.on_resize)\n        self._scene_canvas.events.draw.connect(self.on_draw, position=\'last\')\n        self.viewer.cursor.events.style.connect(self._on_cursor)\n        self.viewer.cursor.events.size.connect(self._on_cursor)\n        # position=first is important to some downstream components such as\n        # scale_bar overlay which need to have access to the updated color\n        # by the time they get updated as well\n        self.viewer.events.theme.connect(\n            self._on_theme_change, position=\'first\'\n        )\n\n        self.viewer.camera.events.mouse_pan.connect(self._on_interactive)\n        self.viewer.camera.events.mouse_zoom.connect(self._on_interactive)\n        self.viewer.camera.events.zoom.connect(self._on_cursor)\n\n        self.viewer._zoom_box.events.zoom_area.connect(self._on_boxzoom)\n        self.viewer.layers.events.reordered.connect(self._update_scenegraph)\n        self.viewer.layers.events.removed.connect(self._remove_layer)\n        self.viewer.layers.events.begin_batch.connect(\n            self._pause_scene_graph_update\n        )\n        self.viewer.layers.events.end_batch.connect(\n            self._resume_scene_graph_update\n        )\n        self.viewer.layers.events.units.connect(\n            self._deferred_world_units_update\n        )\n        self.viewer.grid.events.stride.connect(self._update_scenegraph)\n        self.viewer.grid.events.shape.connect(self._update_scenegraph)\n        self.viewer.grid.events.enabled.connect(self._update_scenegraph)\n        self.viewer.grid.events.spacing.connect(self._update_scenegraph)\n        self.viewer._overlays.events.added.connect(\n            self._update_viewer_overlays\n        )\n        self.viewer._overlays.events.removed.connect(\n            self._update_viewer_overlays\n        )\n        self.viewer._overlays.events.changed.connect(\n            self._update_viewer_overlays\n        )\n        self.destroyed.connect(self._disconnect_events)\n\n    @property\n    def events(self):\n        # This is backwards compatible with the old events system\n        # https://github.com/napari/napari/issues/7054#issuecomment-2205548968\n        return self._scene_canvas.events\n\n    @property\n    def destroyed(self) -> pyqtBoundSignal:\n        return self._scene_canvas._backend.destroyed\n\n    @property\n    def native(self) -> CanvasBackendDesktop:\n        """Returns the native widget of the Vispy SceneCanvas."""\n        return self._scene_canvas.native\n\n    @property\n    def screen_changed(self) -> Callable:\n        """Bound method returning signal indicating whether the window screen has changed."""\n        return self._scene_canvas._backend.screen_changed\n\n    @property\n    def background_color_override(self) -> str | npt.ArrayLike | None:\n        """Background color of VispyCanvas.\n\n        When not None, color is shown instead of VispyCanvas.bgcolor.\n        """\n        return self._background_color_override\n\n    @background_color_override.setter\n    def background_color_override(\n        self, value: str | npt.ArrayLike | None\n    ) -> None:\n        self._background_color_override = value\n        self.bgcolor = value or self._last_theme_color\n\n    def _on_theme_change(self, event: Event) -> None:\n        self._set_theme_change(event.value)\n\n    def _set_theme_change(self, theme: str) -> None:\n        from napari.utils.theme import get_theme\n\n        # Note 1. store last requested theme color, in case we need to reuse it\n        # when clearing the background_color_override, without needing to\n        # keep track of the viewer.\n        # Note 2. the reason for using the `as_hex` here is to avoid\n        # `UserWarning` which is emitted when RGB values are above 1\n        self._last_theme_color = transform_color(\n            get_theme(theme).canvas.as_hex()\n        )[0]\n        self.bgcolor = self._last_theme_color\n\n    def _disconnect_events(self) -> None:\n        disconnect_events(self.viewer.events, self)\n        disconnect_events(self.viewer._overlays.events, self)\n        disconnect_events(self.viewer.camera.events, self)\n        disconnect_events(self.viewer.layers.events, self)\n        disconnect_events(self.viewer.camera.events, self)\n        disconnect_events(self.viewer.cursor.events, self)\n        disconnect_events(self._scene_canvas.events, self)\n\n    @property\n    def bgcolor(self) -> str:\n        """Background color of the vispy scene canvas as a hex string. The setter expects str\n        (any in vispy.color.get_color_names) or hex starting with # or a tuple | np.array ({3,4},)\n        with values between 0 and 1."""\n        return self._scene_canvas.bgcolor.hex\n\n    @bgcolor.setter\n    def bgcolor(self, value: str | npt.ArrayLike) -> None:\n        self._scene_canvas.bgcolor = self._background_color_override or value\n\n    @property\n    def central_widget(self) -> Widget:\n        """Overrides SceneCanvas.central_widget to make border_width=0"""\n        if self._scene_canvas._central_widget is None:\n            self._scene_canvas._central_widget = Widget(\n                size=self.size,\n                parent=self._scene_canvas.scene,\n                border_width=0,\n            )\n        return self._scene_canvas._central_widget\n\n    @property\n    def size(self) -> tuple[int, int]:\n        """Return canvas size as tuple (height, width) or accepts size as tuple (height, width)\n        and sets Vispy SceneCanvas size as (width, height)."""\n        return self._scene_canvas.size[::-1]\n\n    @size.setter\n    def size(self, size: tuple[int, int]):\n        self._scene_canvas.size = size[::-1]\n\n    @property\n    def cursor(self) -> QCursor:\n        """Cursor associated with native widget"""\n        return self.native.cursor()\n\n    @cursor.setter\n    def cursor(self, q_cursor: QCursor | Qt.CursorShape):\n        """Setting the cursor of the native widget"""\n        self.native.setCursor(q_cursor)\n\n    def _on_cursor(self) -> None:\n        """Create a QCursor based on the napari cursor settings and set in Vispy."""\n        cursor = self.viewer.cursor.style\n        brush_overlay = self.viewer._brush_circle_overlay\n        brush_overlay.visible = False\n\n        if cursor in {\'square\', \'circle\', \'circle_frozen\'}:\n            # Scale size by zoom if needed\n            size = self.viewer.cursor.size\n            if self.viewer.cursor.scaled:\n                size *= self.viewer.camera.zoom\n\n            size = int(size)\n\n            # make sure the square fits within the current canvas\n            if (\n                size < 8 or size > (min(*self.size) - 4)\n            ) and cursor != \'circle_frozen\':\n                self.cursor = QtCursorVisual[\'cross\'].value\n            elif cursor.startswith(\'circle\'):\n                brush_overlay.size = size\n                if cursor == \'circle_frozen\':\n                    self.cursor = QtCursorVisual[\'standard\'].value\n                    brush_overlay.position_is_frozen = True\n                else:\n                    self.cursor = QtCursorVisual.blank()\n                    brush_overlay.position_is_frozen = False\n                brush_overlay.visible = True\n            else:\n                self.cursor = QtCursorVisual.square(size)\n        elif cursor == \'crosshair\':\n            self.cursor = QtCursorVisual.crosshair()\n        else:\n            self.cursor = QtCursorVisual[cursor].value\n\n    def delete(self) -> None:\n        """Schedules the native widget for deletion"""\n        self.native.deleteLater()\n\n    def _on_interactive(self) -> None:\n        """Link interactive attributes of view and viewer."""\n        # Is this should be changed or renamed?\n        interactive = (\n            self.viewer.camera.mouse_zoom or self.viewer.camera.mouse_pan\n        )\n        if self.viewer.grid.enabled:\n            self.view.interactive = False\n            self.grid.interactive = interactive\n        else:\n            self.view.interactive = interactive\n            self.grid.interactive = False\n\n    def _on_boxzoom(\n        self, zoom_area: tuple[tuple[float, float], tuple[float, float]]\n    ) -> None:\n        """Update zoom level."""\n        box_size_canvas = np.abs(\n            np.diff(self.viewer._zoom_box.position, axis=0)\n        )\n        box_center_world = np.mean(zoom_area, axis=0)\n        ratio = np.min(self._current_viewbox_size / box_size_canvas)\n        self.viewer.camera.zoom = self.viewer.camera.zoom * np.min(ratio)\n        self.viewer.camera.center = box_center_world\n\n    def _map_canvas2world(\n        self,\n        position: tuple[int, ...],\n        view: ViewBox,\n    ) -> tuple[float, float]:\n        """Map position from canvas pixels into world coordinates.\n\n        Parameters\n        ----------\n        position : list(int, int)\n            Position in canvas (x, y).\n\n        Returns\n        -------\n        coords : tuple of two floats\n            Position in world coordinates, matches the total dimensionality\n            of the viewer.\n        """\n        nd = self.viewer.dims.ndisplay\n\n        transform = view.transform * view.scene.transform\n\n        # cartesian to homogeneous coordinates\n        mapped_position = transform.imap(list(position))\n        if nd == 3:\n            mapped_position = mapped_position[0:nd] / mapped_position[nd]\n        else:\n            mapped_position = mapped_position[0:nd]\n        position_world_slice = np.array(mapped_position[::-1])\n        # handle position for 3D views of 2D data\n        nd_point = len(self.viewer.dims.point)\n        if nd_point < nd:\n            position_world_slice = position_world_slice[-nd_point:]\n\n        position_world = list(self.viewer.dims.point)\n        for i, d in enumerate(self.viewer.dims.displayed):\n            position_world[d] = position_world_slice[i]\n\n        return tuple(position_world)\n\n    def _get_viewbox_at(self, position):\n        """Get the viewbox and its grid coordinates from the mouse position.\n\n        Returns (None, None) when the view is empty (no layers).\n        """\n        if not self.viewer.grid.enabled:\n            return self.view, (0, 0)\n\n        # loop through all viewboxes to check whether the click is inside\n        for (grid_coords, layer_indices), viewbox in zip(\n            self.viewer.grid.iter_viewboxes(len(self.viewer.layers)),\n            self.grid_views,\n            strict=False,\n        ):\n            if not layer_indices:\n                # this is an empty viewbox and we never want to return it,\n                # so we can just skip the check and if it is the actually clicked\n                # one it will return None, None\n                continue\n\n            shifted_pos = position - viewbox.transform.translate[:2]\n            if viewbox.inner_rect.contains(*shifted_pos):\n                return viewbox, grid_coords\n\n        return None, None\n\n    def _process_mouse_event(\n        self, mouse_callbacks: Callable, event: MouseEvent\n    ) -> None:\n        """Add properties to the mouse event before passing the event to the\n        napari events system. Called whenever the mouse moves or is clicked.\n        As such, care should be taken to reduce the overhead in this function.\n        In future work, we should consider limiting the frequency at which\n        it is called.\n\n        This method adds following:\n            position: the position of the click in world coordinates.\n            view_direction: a unit vector giving the direction of the camera in\n                world coordinates.\n            up_direction: a unit vector giving the direction of the camera that is\n                up in world coordinates.\n            dims_displayed: a list of the dimensions currently being displayed\n                in the viewer. This comes from viewer.dims.displayed.\n            dims_point: the indices for the data in view in world coordinates.\n                This comes from viewer.dims.point\n\n        Parameters\n        ----------\n        mouse_callbacks : Callable\n            Mouse callbacks function.\n        event : vispy.app.canvas.MouseEvent\n            The vispy mouse event that triggered this method.\n\n        Returns\n        -------\n        None\n        """\n        if event.pos is None:\n            return\n\n        # ensure that events which began in a specific viewbox continue to be\n        # calculated based on that viewbox\'s coordinates\n        if event.press_event is not None:\n            viewbox, grid_coords = self._get_viewbox_at(event.press_event.pos)\n        else:\n            viewbox, grid_coords = self._get_viewbox_at(event.pos)\n\n        self.viewer.cursor.viewbox = grid_coords\n\n        if viewbox is None:\n            # this means we\'re in an empty viewbox, so do nothing\n            event.handled = True\n            return\n\n        napari_event = NapariMouseEvent(\n            event=event,\n            view_direction=self._calculate_view_direction(event.pos),\n            up_direction=self.viewer.camera.calculate_nd_up_direction(\n                self.viewer.dims.ndim, self.viewer.dims.displayed\n            ),\n            camera_zoom=self.viewer.camera.zoom,\n            position=self._map_canvas2world(event.pos, viewbox),\n            dims_displayed=list(self.viewer.dims.displayed),\n            dims_point=list(self.viewer.dims.point),\n            viewbox=grid_coords,\n        )\n\n        # Update the cursor position\n        self.viewer.cursor._view_direction = napari_event.view_direction\n        self.viewer.cursor.position = napari_event.position\n\n        # Put a read only wrapper on the event\n        read_only_event = ReadOnlyWrapper(\n            napari_event, exceptions=(\'handled\',)\n        )\n        mouse_callbacks(self.viewer, read_only_event)\n\n        layer = self.viewer.layers.selection.active\n        if layer is not None:\n            mouse_callbacks(layer, read_only_event)\n\n        event.handled = napari_event.handled\n\n    def _on_mouse_double_click(self, event: MouseEvent) -> None:\n        """Called whenever a mouse double-click happen on the canvas\n\n        Parameters\n        ----------\n        event : vispy.app.canvas.MouseEvent\n            The vispy mouse event that triggered this method. The `event.type` will always be `mouse_double_click`\n\n        Returns\n        -------\n        None\n\n        Notes\n        -----\n\n        Note that this triggers in addition to the usual mouse press and mouse release.\n        Therefore a double click from the user will likely triggers the following event in sequence:\n\n             - mouse_press\n             - mouse_release\n             - mouse_double_click\n             - mouse_release\n        """\n        self._process_mouse_event(mouse_double_click_callbacks, event)\n\n    def _on_mouse_move(self, event: MouseEvent) -> None:\n        """Called whenever mouse moves over canvas.\n\n        Parameters\n        ----------\n        event : vispy.event.Event\n            The vispy event that triggered this method.\n\n        Returns\n        -------\n        None\n        """\n        self._process_mouse_event(mouse_move_callbacks, event)\n\n    def _on_mouse_press(self, event: MouseEvent) -> None:\n        """Called whenever mouse pressed in canvas.\n\n        Parameters\n        ----------\n        event : vispy.app.canvas.MouseEvent\n            The vispy mouse event that triggered this method.\n\n        Returns\n        -------\n        None\n        """\n        self._process_mouse_event(mouse_press_callbacks, event)\n\n    def _on_mouse_release(self, event: MouseEvent) -> None:\n        """Called whenever mouse released in canvas.\n\n        Parameters\n        ----------\n        event : vispy.app.canvas.MouseEvent\n            The vispy mouse event that triggered this method.\n\n        Returns\n        -------\n        None\n        """\n        self._process_mouse_event(mouse_release_callbacks, event)\n\n    def _on_mouse_wheel(self, event: MouseEvent) -> None:\n        """Called whenever mouse wheel activated in canvas.\n\n        Parameters\n        ----------\n        event : vispy.app.canvas.MouseEvent\n            The vispy mouse event that triggered this method.\n\n        Returns\n        -------\n        None\n        """\n        self._process_mouse_event(mouse_wheel_callbacks, event)\n\n    @property\n    def _viewbox_corners_in_world(self) -> npt.NDArray:\n        """Location of the corners of canvas in world coordinates.\n\n        Returns\n        -------\n        corners : np.ndarray\n            Coordinates of top left and bottom right canvas pixel in the world.\n        """\n        if self.viewer.grid.enabled and self.grid_views:\n            # they are all the same, just take the first one\n            view = self.grid_views[0]\n        else:\n            view = self.view\n\n        # Find corners of canvas in world coordinates\n        top_left = self._map_canvas2world((0, 0), view)\n        bottom_right = self._map_canvas2world(view.rect.size, view)\n        return np.array([top_left, bottom_right])\n\n    def on_draw(self, event: DrawEvent | None = None) -> None:\n        """Called whenever the canvas is drawn.\n\n        This is triggered from vispy whenever new data is sent to the canvas or\n        the camera is moved and is connected in the `QtViewer`.\n\n        Parameters\n        ----------\n        event : vispy.app.canvas.DrawEvent\n            The draw event from the vispy canvas.\n\n        Returns\n        -------\n        None\n        """\n        # this updates camera zooms and overlay positions if necessary\n        # (usually after grid mode enable when viewboxes are still degenerate)\n        if not np.allclose(\n            self._last_viewbox_size, self._current_viewbox_size\n        ):\n            self._update_grid_spacing()\n            self._last_viewbox_size = self._current_viewbox_size\n            self._needs_overlay_position_update = True\n\n        if self._needs_overlay_position_update:\n            self._update_overlay_canvas_positions()\n            self._needs_overlay_position_update = False\n\n        if self._needs_world_units_update:\n            self._update_world_units()\n            self._needs_world_units_update = False\n\n        # sync all cameras\n        for camera in (self.camera, *self.grid_cameras):\n            camera.on_draw(event)\n\n        # The canvas corners in full world coordinates (i.e. across all layers).\n        viewbox_corners_world = self._viewbox_corners_in_world\n        for layer in self.viewer.layers:\n            # The following condition should mostly be False. One case when it can\n            # be True is when a callback connected to self.viewer.dims.events.ndisplay\n            # is executed before layer._slice_input has been updated by another callback\n            # (e.g. when changing self.viewer.dims.ndisplay from 3 to 2).\n            displayed_sorted = sorted(layer._slice_input.displayed)\n            nd = len(displayed_sorted)\n            if nd > self.viewer.dims.ndisplay:\n                displayed_axes = displayed_sorted\n            else:\n                displayed_axes = list(self.viewer.dims.displayed[-nd:])\n            layer._update_draw(\n                scale_factor=1 / self.viewer.camera.zoom,\n                corner_pixels_displayed=viewbox_corners_world[\n                    :, displayed_axes\n                ],\n                shape_threshold=self._current_viewbox_size[::-1],\n            )\n\n    def on_resize(self, event: ResizeEvent) -> None:\n        """Called whenever canvas is resized.\n\n        Parameters\n        ----------\n        event : vispy.app.canvas.ResizeEvent\n            The vispy event that triggered this method.\n\n        Returns\n        -------\n        None\n        """\n        self.viewer._canvas_size = self.size\n\n    def add_layer_visual_mapping(\n        self, napari_layer: Layer, vispy_layer: VispyBaseLayer\n    ) -> None:\n        """Maps a napari layer to its corresponding vispy layer and sets the parent scene of the vispy layer.\n\n        Parameters\n        ----------\n        napari_layer :\n            Any napari layer, the layer type is the same as the vispy layer.\n        vispy_layer :\n            Any vispy layer, the layer type is the same as the napari layer.\n\n        Returns\n        -------\n        None\n        """\n        self.layer_to_visual[napari_layer] = vispy_layer\n        self._layer_overlay_to_visual[napari_layer] = {}\n\n        napari_layer.events.visible.connect(self._reorder_layers)\n        overlay_callback = partial(self._update_layer_overlays, napari_layer)\n        napari_layer.events.visible.connect(overlay_callback)\n        napari_layer._overlays.events.added.connect(overlay_callback)\n        napari_layer._overlays.events.removed.connect(overlay_callback)\n        napari_layer._overlays.events.changed.connect(overlay_callback)\n        napari_layer.events.units.connect(self._deferred_world_units_update)\n        self._overlay_callbacks[napari_layer] = overlay_callback\n        self.viewer.camera.events.angles.connect(vispy_layer._on_camera_move)\n        self._update_world_units()\n\n        # we need to trigger _on_matrix_change once after adding the overlays so that\n        # all children nodes are assigned the correct transforms\n        vispy_layer._on_matrix_change()\n        self._update_scenegraph()\n\n    def _deferred_world_units_update(self):\n        """Defer the world units update until the next draw event."""\n        self._needs_world_units_update = True\n\n    def _update_world_units(self):\n        """Update the units of the canvas and all layers."""\n        units = self.viewer.layers.extent.units\n        if units is None:\n            show_warning(\n                \'Inconsistent units across layers; units will not be used for rendering.\'\n            )\n        for vispy_layer in self.layer_to_visual.values():\n            vispy_layer.world_units = units\n\n    def _remove_layer(self, event: Event) -> None:\n        """Upon receiving event closes the Vispy visual, deletes it and reorders the still existing layers.\n\n        Parameters\n        ----------\n        event : napari.utils.events.event.Event\n            The event causing a particular layer to be removed\n\n        Returns\n        -------\n        None\n        """\n        layer = event.value\n        disconnect_events(layer.events, self)\n        disconnect_events(layer.events, self._overlay_callbacks[layer])\n        disconnect_events(\n            layer._overlays.events, self._overlay_callbacks[layer]\n        )\n        layer.events.units.disconnect(self._deferred_world_units_update)\n        del self._overlay_callbacks[layer]\n\n        vispy_layer = self.layer_to_visual.pop(layer)\n        disconnect_events(self.viewer.camera.events, vispy_layer)\n        vispy_layer.close()\n        del vispy_layer\n\n        self._update_layer_overlays(layer)\n        del self._layer_overlay_to_visual[layer]\n        if self._pause_scene_graph:\n            return\n        self._clean_and_update_scenegraph()\n\n    def _clean_and_update_scenegraph(self):\n        # Critical two-step fix for Windows OpenGL access violation bug\n        # This prevents the race condition where scenegraph updates occur while\n        # GPU resources from the removed layer are still being processed/deleted.\n\n        # Step 1: Force immediate garbage collection of OpenGL resources\n        # When vispy_layer.close() is called above, it marks OpenGL objects (textures,\n        # buffers, etc.) for deletion, but Python\'s garbage collector may not run\n        # immediately. On some Windows OpenGL drivers (especially NVIDIA cards),\n        # this can leave "dangling" OpenGL resource references.\n        gc.collect()\n\n        # Step 2: Synchronize the OpenGL command queue\n        # Layer removal involves deleting GPU textures, buffers, and shader programs/\n        # The subsequent _update_scenegraph() call rebuilds the scene graph with new GPU resources.\n        # If the GPU is still processing deletion commands from the removed layer, it can lead to\n        # memory access violations when the scene graph is updated with new resources.\n        # finish() ensures complete GPU synchronization before proceeding\n        with contextlib.suppress(AttributeError, GLError):\n            # need to suppress the error because of implementation details of vispy\n            self._scene_canvas.context.finish()\n\n        self._update_scenegraph()\n\n    def _reorder_layers(self) -> None:\n        """When the list is reordered, propagate changes to draw order."""\n        if self.viewer.grid.enabled:\n            for _, layer_indices in self.viewer.grid.iter_viewboxes(\n                len(self.viewer.layers)\n            ):\n                if not layer_indices:\n                    continue\n                layers = [self.viewer.layers[idx] for idx in layer_indices]\n                self._reorder_layers_in_the_same_view(layers)\n        else:\n            self._reorder_layers_in_the_same_view(self.viewer.layers)\n\n    def _reorder_layers_in_the_same_view(self, layers):\n        first_visible_found = False\n\n        for i, layer in enumerate(layers):\n            vispy_layer = self.layer_to_visual[layer]\n            vispy_layer.order = i\n\n            # the bottommost visible layer needs special treatment for blending\n            if layer.visible and not first_visible_found:\n                vispy_layer.first_visible = True\n                first_visible_found = True\n            else:\n                vispy_layer.first_visible = False\n            vispy_layer._on_blending_change()\n\n        self._defer_overlay_position_update()\n\n        self._scene_canvas._draw_order.clear()\n        self._scene_canvas.update()\n\n    def _defer_overlay_position_update(self):\n        self._needs_overlay_position_update = True\n\n    def _connect_canvas_overlay_events(self, overlay: Overlay) -> None:\n        overlay.events.position.connect(\n            self._update_overlay_canvas_positions, unique=True\n        )\n        overlay.events.visible.connect(\n            self._update_overlay_canvas_positions, unique=True\n        )\n\n    def _disconnect_canvas_overlay_events(self, overlay: Overlay) -> None:\n        overlay.events.position.disconnect(\n            self._update_overlay_canvas_positions\n        )\n        overlay.events.visible.disconnect(\n            self._update_overlay_canvas_positions\n        )\n\n    def _create_or_update_vispy_viewer_overlay(\n        self,\n        overlay: Overlay,\n        vispy_overlay: VispyBaseOverlay | None,\n        view: ViewBox,\n    ) -> None:\n        parent = view if isinstance(overlay, CanvasOverlay) else view.scene\n\n        if vispy_overlay is None:\n            vispy_overlay = create_vispy_overlay(\n                overlay=overlay,\n                viewer=self.viewer,\n                parent=parent,\n                font_manager=self._font_manager,\n                font_family=self._overlay_font,\n            )\n            self._overlay_to_visual[overlay].append(vispy_overlay)\n\n            if isinstance(overlay, CanvasOverlay):\n                vispy_overlay.canvas_position_callback = (\n                    self._defer_overlay_position_update\n                )\n\n        else:\n            vispy_overlay.node.parent = parent\n            if isinstance(overlay, CanvasOverlay):\n                vispy_overlay._on_box_change()\n\n    def _update_viewer_overlays(self):\n        """Update the viewer overlay visuals.\n\n        Also ensures that overlays are properly assigned parents depending on\n        their class (canvas vs scene overlays).\n        """\n        # delete outdated overlays\n        for overlay in set(self._overlay_to_visual) - set(\n            self.viewer._overlays.values()\n        ):\n            if isinstance(overlay, CanvasOverlay):\n                self._disconnect_canvas_overlay_events(overlay)\n            vispy_overlays = self._overlay_to_visual.pop(overlay)\n            for vispy_overlay in vispy_overlays:\n                vispy_overlay.close()\n\n        # go through all overlays and ensure there are the exact amount of\n        # corresponding visuals depending on number of views to display\n        for overlay in self.viewer._overlays.values():\n            # only create overlays when they are visible. If not, we connect the visible\n            # event of this overlay to this method until it\'s finally visible\n            if not overlay.visible:\n                overlay.events.visible.connect(\n                    self._update_viewer_overlays, unique=True\n                )\n                continue\n            overlay.events.visible.disconnect(self._update_viewer_overlays)\n\n            vispy_overlays = self._overlay_to_visual.setdefault(overlay, [])\n\n            gridded = (\n                self.viewer.grid.enabled\n                and getattr(\n                    overlay, \'gridded\', True\n                )  # scene overlays always gridded\n                and self.viewer.layers\n            )\n\n            # delete redundant vispy overlays (always keep 1)\n            n_views_to_populate = (\n                len(self.viewer.layers) // abs(self.viewer.grid.stride) or 1\n                if gridded\n                else 1\n            )\n            while len(vispy_overlays) > n_views_to_populate:\n                vispy_overlays.pop().close()\n\n            # create, or update parent if existing\n            if gridded:\n                for ((row, col), layer_indices), vispy_overlay in zip_longest(\n                    self.viewer.grid.iter_viewboxes(len(self.viewer.layers)),\n                    list(vispy_overlays),\n                ):\n                    if not layer_indices:\n                        # no overlays should be displayed in empty viewboxes\n                        continue\n\n                    view: ViewBox = self.grid[row, col]\n                    self._create_or_update_vispy_viewer_overlay(\n                        overlay, vispy_overlay, view\n                    )\n            else:\n                view = self.view\n                vispy_overlay = vispy_overlays[0] if vispy_overlays else None\n                self._create_or_update_vispy_viewer_overlay(\n                    overlay, vispy_overlay, view\n                )\n\n            # connect position callbacks\n            if isinstance(overlay, CanvasOverlay):\n                self._connect_canvas_overlay_events(overlay)\n                overlay.events.gridded.connect(\n                    self._update_viewer_overlays, unique=True\n                )\n\n        self._update_overlay_canvas_positions()\n\n    def _update_layer_overlays(self, layer: Layer) -> None:\n        """Update the overlay visuals for each layer in the canvas.\n\n        Also ensures that overlays are properly assigned parents depending on\n        their class (canvas vs scene overlays).\n        """\n        overlay_to_visual = self._layer_overlay_to_visual.setdefault(layer, {})\n\n        # delete outdated overlays\n        if layer not in self.viewer.layers:\n            to_remove = set(layer._overlays.values())\n        else:\n            to_remove = set(overlay_to_visual.keys()) - set(\n                layer._overlays.values()\n            )\n\n        for overlay in to_remove:\n            if isinstance(overlay, CanvasOverlay):\n                self._disconnect_canvas_overlay_events(overlay)\n            if vispy_overlay := overlay_to_visual.pop(overlay, None):\n                vispy_overlay.close()\n\n        if layer not in self.viewer.layers:\n            # we\'re just removing all the overlays of this layer, so we\'re done here\n            return\n\n        for overlay in layer._overlays.values():\n            # only create overlays when they are visible. If not, we connect the visible\n            # event of this overlay to this method until it\'s finally visible\n            if not overlay.visible:\n                overlay.events.visible.connect(\n                    self._overlay_callbacks[layer], unique=True\n                )\n                continue\n            overlay.events.visible.disconnect(self._overlay_callbacks[layer])\n\n            vispy_overlay = overlay_to_visual.get(overlay, None)\n\n            if isinstance(overlay, CanvasOverlay):\n                self._connect_canvas_overlay_events(overlay)\n\n                if self.viewer.grid.enabled:\n                    row, col = self.viewer.grid.position(\n                        self.viewer.layers.index(layer),\n                        len(self.viewer.layers),\n                    )\n                    parent = self.grid[row, col]\n                else:\n                    parent = self.view\n            else:\n                parent = self.layer_to_visual[layer].node\n\n            if vispy_overlay is None:\n                vispy_overlay = create_vispy_overlay(\n                    overlay=overlay,\n                    layer=layer,\n                    viewer=self.viewer,\n                    parent=parent,\n                    font_manager=self._font_manager,\n                    font_family=self._overlay_font,\n                )\n                overlay_to_visual[overlay] = vispy_overlay\n                if isinstance(overlay, CanvasOverlay):\n                    vispy_overlay.canvas_position_callback = (\n                        self._defer_overlay_position_update\n                    )\n            else:\n                vispy_overlay.node.parent = parent\n                if isinstance(overlay, CanvasOverlay):\n                    vispy_overlay._on_box_change()\n\n        self._update_overlay_canvas_positions()\n\n    def _get_ordered_visible_canvas_overlays(\n        self,\n    ) -> Iterator[tuple[CanvasOverlay, VispyBaseOverlay, Node | None]]:\n        """\n        Iterator over visible canvas overlays by grid viewbox, in tiling order.\n\n        Returns a tuple containing the overlay model, its matching visual, and\n        the index of the view in the grid where the overlay should be displayed.\n        The view `None` is special cased to refer to the base, non-gridded view.\n\n        Note that some canvas overlays do no use CanvasPosition, but are instead\n        free-floating (such as the cursor overlay), so those are skipped\n        """\n\n        def is_visible_tileable(overlay):\n            return (\n                overlay.visible\n                and isinstance(overlay, CanvasOverlay)\n                and overlay.position in list(CanvasPosition)\n            )\n\n        def is_gridded(overlay):\n            return (\n                overlay.gridded\n                and self.viewer.grid.enabled\n                and self.viewer.layers\n            )\n\n        # first the base view: non-gridded viewer overlays which appear\n        # "on top of" the main canvas\n        for overlay, vispy_overlays in self._overlay_to_visual.items():\n            if (\n                vispy_overlays\n                and is_visible_tileable(overlay)\n                and not is_gridded(overlay)\n            ):\n                yield overlay, vispy_overlays[0], None\n\n        # then gridded viewer overlays and layer overlays, by viewbox, in order\n        for viewbox_idx, (_, layer_indices) in enumerate(\n            self.viewer.grid.iter_viewboxes(len(self.viewer.layers))\n        ):\n            if not layer_indices:\n                # last empty boxes of the grid\n                break\n\n            # if grid is disabled, this loop runs once and we put everything\n            # in the base (None) viewbox\n            view = (\n                viewbox_idx\n                if self.viewer.grid.enabled and self.viewer.layers\n                else None\n            )\n\n            for overlay, vispy_overlays in self._overlay_to_visual.items():\n                if (\n                    vispy_overlays\n                    and is_visible_tileable(overlay)\n                    and is_gridded(overlay)\n                ):\n                    yield overlay, vispy_overlays[viewbox_idx], view\n\n            # we want to ensure that the tiling of layer overlays always looks\n            # the same as the llayerlist order, so we reverse the direction for\n            # some cases\n            overlays_by_tiling_order = {\'direct\': [], \'reversed\': []}\n\n            # layer overlays are always "gridded"\n            # (they always appear in the same viewbox as the layer itself)\n            for layer_idx in layer_indices:\n                layer = self.viewer.layers[layer_idx]\n                for (\n                    overlay,\n                    vispy_overlay,\n                ) in self._layer_overlay_to_visual.get(layer, {}).items():\n                    if layer.visible and is_visible_tileable(overlay):\n                        # TODO: this should check for tiling direction when it becomes settable\n                        if overlay.position in (\n                            CanvasPosition.TOP_LEFT,\n                            CanvasPosition.TOP_CENTER,\n                            CanvasPosition.BOTTOM_LEFT,\n                        ):\n                            direction = \'reversed\'\n                        else:\n                            direction = \'direct\'\n                        overlays_by_tiling_order[direction].append(\n                            (overlay, vispy_overlay, view)\n                        )\n\n            yield from reversed(overlays_by_tiling_order[\'reversed\'])\n            yield from overlays_by_tiling_order[\'direct\']\n\n    def _update_overlay_canvas_positions(self, event=None):\n        # TODO: make settable\n        x_padding = y_padding = 10.0\n        x_offset_total = {}\n        y_offset_total = {}\n        for (\n            overlay,\n            vispy_overlay,\n            view,\n        ) in self._get_ordered_visible_canvas_overlays():\n            # TODO: vertical vs horizontal tiling should be settable!\n            x_offset_total.setdefault(\n                view, dict.fromkeys(CanvasPosition, x_padding)\n            )\n            y_offset_total.setdefault(\n                view, dict.fromkeys(CanvasPosition, y_padding)\n            )\n\n            x_offset = x_offset_total[view][overlay.position]\n            y_offset = y_offset_total[view][overlay.position]\n\n            # add offset to the following overlays based on tiling direction\n            # these are currently hardcoded, so we just tile horizontally or\n            # vertically depending on which corner we\'re on\n            if overlay.position in (\'top_right\', \'bottom_left\'):\n                x_offset_total[view][overlay.position] += (\n                    vispy_overlay.x_size + x_padding\n                )\n            else:\n                y_offset_total[view][overlay.position] += (\n                    vispy_overlay.y_size + y_padding\n                )\n\n            # position the overlay in the canvas\n            # if the overlay is in a grid viewbox, use the viewbox size\n            if view is None:\n                y_max, x_max = self.size\n            else:\n                x_max, y_max = self._current_viewbox_size\n            position = overlay.position\n\n            x = y = 0\n            if \'top\' in position:\n                y = y_offset\n            elif \'bottom\' in position:\n                y = y_max - vispy_overlay.y_size - y_offset\n\n            if \'left\' in position:\n                x = x_offset\n            elif \'right\' in position:\n                x = x_max - vispy_overlay.x_size - x_offset\n            elif \'center\' in position:\n                x = x_max / 2 - vispy_overlay.x_size / 2\n\n            vispy_overlay.node.transform.translate = [x, y, 0, 0]\n\n        self._needs_overlay_position_update = False\n\n    def _calculate_view_direction(\n        self, event_pos: tuple[float, float]\n    ) -> npt.NDArray[np.float64] | None:\n        """calculate view direction by ray shot from the camera"""\n        # this method is only implemented for 3 dimension\n        if self.viewer.dims.ndisplay == 2:\n            return None\n\n        if self.viewer.dims.ndim == 2:\n            return self.viewer.camera.calculate_nd_view_direction(\n                self.viewer.dims.ndim, self.viewer.dims.displayed\n            )\n        x, y = event_pos\n        w, h = self.size\n        nd = self.viewer.dims.ndisplay\n\n        view = self._get_viewbox_at(event_pos)[0] or self.view\n        # combine the viewbox transform wit the scene transform\n        # so each viewbox in grid mode maps back to the main scene\n        transform = view.transform * view.scene.transform\n\n        # map click pos to scene coordinates\n        click_scene = transform.imap([x, y, 0, 1])\n        # canvas center at infinite far z- (eye position in canvas coordinates)\n        eye_canvas = [w / 2, h / 2, -1e10, 1]\n        # map eye pos to scene coordinates\n        eye_scene = transform.imap(eye_canvas)\n        # homogeneous coordinate to cartesian\n        click_scene = click_scene[0:nd] / click_scene[nd]\n        # homogeneous coordinate to cartesian\n        eye_scene = eye_scene[0:nd] / eye_scene[nd]\n\n        # calculate direction of the ray\n        d = click_scene - eye_scene\n        d = d[0:nd]\n        d = d / np.linalg.norm(d)\n        # xyz to zyx\n        d: list[float] = list(d[::-1])\n        # convert to nd view direction\n        view_direction_nd = np.zeros(self.viewer.dims.ndim, dtype=np.float64)\n        view_direction_nd[list(self.viewer.dims.displayed)] = d\n        return view_direction_nd\n\n    def screenshot(self) -> QImage:\n        """Return a QImage based on what is shown in the viewer."""\n        # ensure on_draw is run to bring everything up to date\n        # needed for some Ubuntu py3.10 pyqt5 tests, but likely inconsistent behavior for other OS.\n        # See: https://github.com/napari/napari/pull/7870#issuecomment-2997167180\n        self.on_draw(None)\n        return self.native.grabFramebuffer()\n\n    def enable_dims_play(self, *args) -> None:\n        """Enable playing of animation. False if awaiting a draw event"""\n        self.viewer.dims._play_ready = True\n\n    def _init_or_update_grid(self) -> None:\n        # grid are really not designed to be reset, so we have to replace it\n        # when necessary (every time the grid shape changes)\n        if self.grid.grid_size == self.viewer.grid.actual_shape(\n            len(self.viewer.layers)\n        ):\n            return\n\n        for camera in self.grid_cameras:\n            self._scene_canvas.events.draw.disconnect(camera.on_draw)\n            camera._2D_camera.parent = None\n            camera._3D_camera.parent = None\n        self.grid_cameras.clear()\n        self.grid_views.clear()\n        self.grid.parent = None\n\n        self.grid = self.central_widget.add_grid(border_width=0)\n\n        for (row, col), _ in self.viewer.grid.iter_viewboxes(\n            len(self.viewer.layers)\n        ):\n            view = self.grid[row, col]\n            # any border_color != None will add a padding of +1\n            # see https://github.com/vispy/vispy/issues/1492\n            view.border_width = 0\n            view.border_color = None\n\n            camera = VispyCamera(view, self.viewer.camera, self.viewer.dims)\n            self.grid_views.append(view)\n            self.grid_cameras.append(camera)\n\n    def _update_scenegraph(self, event=None):\n        if self._pause_scene_graph:\n            return\n        with self._scene_canvas.events.draw.blocker():\n            if self.viewer.grid.enabled:\n                self._init_or_update_grid()\n                self._setup_layer_views_in_grid()\n                self._update_grid_spacing()\n            else:\n                self._setup_single_view()\n\n            self._reorder_layers()\n            self._update_viewer_overlays()\n            for layer in self.viewer.layers:\n                self._update_layer_overlays(layer)\n            self._on_interactive()\n        self.on_draw(None)\n\n    def _setup_single_view(self):\n        for vispy_layer in self.layer_to_visual.values():\n            vispy_layer.node.parent = self.view.scene\n\n    def _setup_layer_views_in_grid(self):\n        for (row, col), layer_indices in self.viewer.grid.iter_viewboxes(\n            len(self.viewer.layers)\n        ):\n            view = self.grid[row, col]\n\n            for idx in layer_indices:\n                napari_layer = self.viewer.layers[idx]\n                vispy_layer = self.layer_to_visual[napari_layer]\n                vispy_layer.node.parent = view.scene\n\n    @property\n    def _current_viewbox_size(self):\n        """Get the actual size of the viewboxes in pixels.\n\n        If grid is not enabled, this returns the size of the canvas.\n        If grid is enabled, this returns the size of the viewboxes; note that\n        these can be degenerate if `on_draw` hasn\'t been called yet!\n\n        Returns\n        -------\n        tuple[int, int]\n            The size of the viewbox(es) in pixels (width, height)\n        """\n        if self.viewer.grid.enabled and self.grid_views:\n            return self.grid_views[0].rect.size\n\n        return self.view.rect.size\n\n    def _update_grid_spacing(self):\n        """Update the grid spacing with a validated spacing value.\n\n        This method computes the raw spacing based on the current canvas size\n        and validates it against the maximum safe spacing. If the raw spacing\n        exceeds the maximum safe spacing, it is reduced to the maximum safe value\n        and a warning is issued to the user.\n        """\n        # TODO: this should be all handled on the grid model ideally, using validators\n        raw_spacing = self.viewer.grid._compute_canvas_spacing_raw(\n            self._scene_canvas.size, len(self.viewer.layers)\n        )\n        safe_spacing = self.viewer.grid._compute_canvas_spacing(\n            self._scene_canvas.size, len(self.viewer.layers)\n        )\n\n        if raw_spacing > safe_spacing:\n            warnings.warn(\n                trans._(\n                    \'Grid spacing of {raw_spacing:.1f} pixels is too large and has been \'\n                    \'reduced to {safe_spacing:.1f} pixels to prevent viewboxes from \'\n                    \'becoming too small. Consider using a smaller spacing value or \'\n                    \'increasing the canvas size.\',\n                    deferred=True,\n                    raw_spacing=raw_spacing,\n                    safe_spacing=safe_spacing,\n                ),\n                UserWarning,\n                stacklevel=2,\n            )\n            # this shouldn\'t cause an infinite loop cause now the spacing is fixed!\n            self.viewer.grid.spacing = safe_spacing\n\n        self.grid.spacing = safe_spacing\n\n    def _pause_scene_graph_update(self):\n        self._pause_scene_graph = True\n\n    def _resume_scene_graph_update(self):\n        self._pause_scene_graph = False\n        self._clean_and_update_scenegraph()\n',
        }
